INSERT INTO `item` (`itemId`, `name`, `goldSellsFor`, `goldTotal`, `goldBase`, `purchasable`, `colloq`, `description`, `plaintext`, `depth`) VALUES
	(0, 'None', 0, 0, 0, b'0', NULL, NULL, NULL, 1),
	(1001, 'Boots of Speed', 210, 300, 300, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><unique>UNIQUE Passive - Enhanced Movement:</unique> +25 Movement Speed', 'Slightly increases Movement Speed', 1),
	(1004, 'Faerie Charm', 88, 125, 125, b'1', ';', '<stats><mana>+25% Base Mana Regen </mana></stats>', 'Slightly increases Mana Regen', 1),
	(1006, 'Rejuvenation Bead', 105, 150, 150, b'1', ';', '<stats>+50% Base Health Regen </stats>', 'Slightly increases Health Regen', 1),
	(1011, 'Giant\'s Belt', 700, 1000, 600, b'1', ';', '<stats>+380 Health</stats>', 'Greatly increases Health', 2),
	(1026, 'Blasting Wand', 595, 850, 850, b'1', ';', '<stats>+40 Ability Power</stats>', 'Moderately increases Ability Power', 1),
	(1027, 'Sapphire Crystal', 245, 350, 350, b'1', ';blue', '<stats><mana>+250 Mana</mana></stats>', 'Increases Mana', 1),
	(1028, 'Ruby Crystal', 280, 400, 400, b'1', ';red', '<stats>+150 Health</stats>', 'Increases Health', 1),
	(1029, 'Cloth Armor', 210, 300, 300, b'1', ';', '<stats>+15 Armor</stats>', 'Slightly increases Armor', 1),
	(1031, 'Chain Vest', 560, 800, 500, b'1', ';', '<stats>+40 Armor</stats>', 'Greatly increases Armor', 2),
	(1033, 'Null-Magic Mantle', 315, 450, 450, b'1', ';', '<stats>+25 Magic Resist</stats>', 'Slightly increases Magic Resist', 1),
	(1036, 'Long Sword', 245, 350, 350, b'1', ';', '<stats>+10 Attack Damage</stats>', 'Slightly increases Attack Damage', 1),
	(1037, 'Pickaxe', 613, 875, 875, b'1', ';', '<stats>+25 Attack Damage</stats>', 'Moderately increases Attack Damage', 1),
	(1038, 'B. F. Sword', 910, 1300, 1300, b'1', ';bf', '<stats>+40 Attack Damage</stats>', 'Greatly increases Attack Damage', 1),
	(1039, 'Hunter\'s Talisman', 245, 350, 350, b'1', ';jungle;Jungle', '<br><unique>UNIQUE Passive - Tooth:</unique> Damaging a monster with a spell or attack  steals 30 Health over 5 seconds and burns them for 60 magic damage. <mana>While in the jungle or river, regenerate up to 8 Mana per second based on your missing Mana.</mana> This item grants <font color=\'#99BBBB\'><a href=\'SpecialJungleExperience\'>Monster Hunter</a></font>.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Provides damage against Monsters and Mana Regen in the Jungle', 1),
	(1041, 'Hunter\'s Machete', 245, 350, 350, b'1', ';jungle;Jungle', '<stats>+10% Life Steal vs. Monsters</stats><br><br><unique>UNIQUE Passive - Nail:</unique> Basic attacks vs. Monsters deal 35 bonus damage on hit. This item grants <font color=\'#99BBBB\'><a href=\'SpecialJungleExperience\'>Monster Hunter</a></font>.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Provides damage and life steal versus Monsters', 1),
	(1042, 'Dagger', 210, 300, 300, b'1', ';', '<stats>+12% Attack Speed</stats>', 'Slightly increases Attack Speed', 1),
	(1043, 'Recurve Bow', 700, 1000, 400, b'1', ';', '<stats>+25% Attack Speed</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal an additional 15 physical damage on hit.', 'Greatly increases Attack Speed', 2),
	(1051, 'Brawler\'s Gloves', 280, 400, 400, b'1', ';', '<unique>UNIQUE Passive:</unique> +10% Critical Strike Chance', 'Slightly increases Critical Strike Chance', 1),
	(1052, 'Amplifying Tome', 305, 435, 435, b'1', ';amptome', '<stats>+20 Ability Power</stats>', 'Slightly increases Ability Power', 1),
	(1053, 'Vampiric Scepter', 630, 900, 550, b'1', ';', '<stats>+15 Attack Damage<br>+10% Life Steal</stats>', 'Basic attacks restore Health', 2),
	(1054, 'Doran\'s Shield', 180, 450, 450, b'1', ';dshield', '<stats>+80 Health</stats><br><br><passive>Passive: </passive>Restores 6 Health every 5 seconds.<br><passive>Passive: </passive>Basic attacks deal an additional 5 physical damage to minions on hit.<br><unique>UNIQUE Passive:</unique> Regenerate up to 30 health over 10 seconds after taking damage from an enemy champion, based on percent missing health.', 'Good defensive starting item', 1),
	(1055, 'Doran\'s Blade', 180, 450, 450, b'1', ';dblade', '<stats>+8 Attack Damage<br>+80 Health<br>+3% Life Steal</stats>', 'Good starting item for attackers', 1),
	(1056, 'Doran\'s Ring', 160, 400, 400, b'1', ';dring', '<stats>+60 Health<br>+15 Ability Power<br><mana>+5 Mana per 5 seconds</mana></stats><br><br><passive>Passive: </passive>Basic attacks deal an additional 5 physical damage to minions on hit.', 'Good starting item for casters', 1),
	(1057, 'Negatron Cloak', 504, 720, 270, b'1', ';', '<stats>+40 Magic Resist</stats>', 'Moderately increases Magic Resist', 2),
	(1058, 'Needlessly Large Rod', 875, 1250, 1250, b'1', ';nlr', '<stats>+60 Ability Power</stats>', 'Greatly increases Ability Power', 1),
	(1059, 'Space Vampiric Scepter', 630, 900, 550, b'1', ';', '<stats>+15 Attack Damage<br>+2.5% Life Steal</stats>', 'Basic attacks restore Health', 2),
	(1082, 'The Dark Seal', 245, 350, 350, b'1', ';Noxian', '<stats>+15 Ability Power<br>+25% Increased Healing from Potions<br><mana>+100 Mana</mana></stats><br><br><unique>UNIQUE Passive - Dread:</unique> Grants +3 Ability Power per Glory.  <br><unique>UNIQUE Passive - Do or Die:</unique> Grants 2 Glory for a champion kill or 1 Glory for an assist, up to 10 Glory total. Lose 4 Glory on death.', 'Provides Ability Power and Mana.  Increases in power as you kill enemies.', 1),
	(1083, 'Cull', 180, 450, 450, b'1', ';dblade', '<stats>+7 Attack Damage<br>+3 Life on Hit</stats><br><br><unique>UNIQUE Passive:</unique> Killing a lane minion grants 1 additional Gold. Killing 100 lane minions grants an additional 350 bonus gold immediately and disables this passive.', 'Provides damage and Life Steal on hit - Killing minions grant bonus Gold', 1),
	(1400, 'Enchantment: Warrior', 1838, 2625, 525, b'1', '', '<stats>+60 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants Attack Damage and Cooldown Reduction', 3),
	(1401, 'Enchantment: Cinderhulk', 1750, 2500, 600, b'1', '', '<stats>+300 Health<br>+15% Bonus Health</stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 11 (+1 per champion level) magic damage a second to nearby enemies while in combat. Deals 200% bonus damage to minions and monsters.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants Health and Immolate Aura', 3),
	(1402, 'Enchantment: Runic Echoes', 1838, 2625, 375, b'1', '', '<stats>+80 Ability Power<br>+10% Cooldown Reduction<br><mana>+300 Mana</mana></stats><br><br><unique>UNIQUE Passive - Echo:</unique> Gain charges upon moving or casting. At 100 charges, the next damaging spell hit expends all charges to deal 60 (+10% of Ability Power) bonus magic damage to up to 4 targets on hit.<br><br>This effect deals 250% damage to Large Monsters. Hitting a Large Monster with this effect will restore 25% of your missing Mana.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants Ability Power and periodically empowers your Spells', 3),
	(1412, 'Enchantment: Warrior', 1838, 2625, 525, b'1', '', '<stats>+60 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants Attack Damage and Cooldown Reduction', 3),
	(1413, 'Enchantment: Cinderhulk', 1750, 2500, 600, b'1', '', '<stats>+300 Health<br>+15% Bonus Health</stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 11 (+1 per champion level) magic damage a second to nearby enemies while in combat. Deals 200% bonus damage to minions and monsters.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants Health and Immolate Aura', 3),
	(1414, 'Enchantment: Runic Echoes', 1838, 2625, 375, b'1', '', '<stats>+80 Ability Power<br>+10% Cooldown Reduction<br><mana>+300 Mana</mana></stats><br><br><unique>UNIQUE Passive - Echo:</unique> Gain charges upon moving or casting. At 100 charges, the next damaging spell hit expends all charges to deal 60 (+10% of Ability Power) bonus magic damage to up to 4 targets on hit.<br><br>This effect deals 250% damage to Large Monsters. Hitting a Large Monster with this effect will restore 25% of your missing Mana.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants Ability Power and periodically empowers your Spells', 3),
	(1416, 'Enchantment: Bloodrazor', 1838, 2625, 625, b'1', '', '<stats>+50% Attack Speed</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 4% of the target\'s maximum Health in bonus physical damage (max 75 vs. monsters and minions) on hit.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Increases Attack Speed and deals damage based on the target\'s Health', 3),
	(1419, 'Enchantment: Bloodrazor', 1838, 2625, 625, b'1', '', '<stats>+50% Attack Speed</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 4% of the target\'s maximum Health in bonus physical damage (max 75 vs. monsters and minions) on hit.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Increases Attack Speed and deals damage based on the target\'s Health', 3),
	(2003, 'Health Potion', 20, 50, 50, b'1', ';', '<groupLimit>Limited to 5 at one time. Limited to 1 type of Healing Potion.</groupLimit><br><br><consumable>Click to Consume:</consumable> Restores 150 Health over 15 seconds.', 'Consume to restore Health over time', 1),
	(2004, 'Mana Potion', 12, 30, 30, b'0', ';', '<groupLimit>Limited to 5 at one time.</groupLimit><br><br><consumable>Click to Consume:</consumable> <mana>Restores 100 Mana over 15 seconds.</mana>', 'Consume to restore Mana over time', 1),
	(2009, 'Total Biscuit of Rejuvenation', 0, 0, 0, b'0', ';', '<consumable>Click to Consume:</consumable> Restores 80 Health and 50 Mana over 10 seconds.', '', 1),
	(2010, 'Total Biscuit of Everlasting Will', 30, 75, 75, b'0', ';', '<consumable>Click to Consume:</consumable> Restores 15% of missing Health and Mana over 15 seconds.', '', 1),
	(2011, 'Elixir Of Skill', 0, 0, 0, b'0', ';', '<consumable>Click to Consume:</consumable> Grants <font color=\'#29E3D6\'>+1 Skill Point</font>.', '', 1),
	(2012, 'Looted Biscuit of Rejuvenation', 30, 75, 75, b'0', ';', '<consumable>Click to Consume:</consumable> Restores 15% of missing Health and Mana over 15 seconds.', '', 1),
	(2013, 'Looted Oracle\'s Extract', 24, 60, 60, b'0', ';', '<consumable>Click to Consume:</consumable> Grants detection of nearby invisible or unseen enemy units for 15 to 40 seconds, based on level.', 'Allows champion to see invisible or unseen enemy units', 1),
	(2015, 'Kircheis Shard', 560, 800, 500, b'1', ';', '<stats>+15% Attack Speed</stats><br><br><passive>Passive:</passive> Moving and attacking will make an attack <a href=\'Energized\'>Energized</a>.<br><br><unique>UNIQUE Passive - Energized Strike:</unique> Your Energized attacks deal 50 bonus magic damage on hit.', 'Attack speed and a chargable magic hit', 2),
	(2031, 'Refillable Potion', 60, 150, 150, b'1', ';', '<groupLimit>Limited to 1 type of Healing Potion.</groupLimit><br><br><active>UNIQUE Active:</active> Consumes a charge to restore 125 Health over 12 seconds. Holds up to 2 charges and refills upon visiting the shop.', 'Restores Health over time. Refills at shop.', 1),
	(2032, 'Hunter\'s Potion', 160, 400, 250, b'1', ';', '<groupLimit>Limited to 1 type of Healing Potion.</groupLimit><br><br><active>UNIQUE Active:</active> Consumes a charge to restore 60 Health and 35 Mana over 8 seconds. Holds up to 5 charges and refills upon visiting the shop.<br><br>Killing a Large Monster grants 1 charge.<br><br><rules>(Killing a Large Monster at full charges will automatically consume the newest charge.)</rules>', 'Restores Health and Mana over time - Refills at shop and has increased capacity', 2),
	(2033, 'Corrupting Potion', 200, 500, 350, b'1', ';', '<groupLimit>Limited to 1 type of Healing Potion.</groupLimit><br><br><active>UNIQUE Active:</active> Consumes a charge to restore 125 Health and 75 Mana over 12 seconds and grants <font color=\'#FF8811\'><u>Touch of Corruption</u></font> during that time. Holds up to 3 charges that refills upon visiting the shop.<br><br><font color=\'#FF8811\'><u>Touch of Corruption:</u></font> Damaging spells and attacks burn enemy champions for <scaleLevel>15 - 30</scaleLevel> magic damage over 3 seconds. (Half Damage for Area of Effect or Damage over Time spells. Damage increases with champion level.)<br><br><rules>(Corrupting Potion can be used even at full Health and Mana.)</rules>', 'Restores Health and Mana over time and boosts combat power - Refills at Shop', 2),
	(2047, 'Oracle\'s Extract', 120, 300, 300, b'1', ';', '<consumable>Click to Consume:</consumable> Grants detection of nearby invisible or unseen enemy units for 5 minutes.', 'Allows champion to see invisible or unseen enemy units', 1),
	(2050, 'Explorer\'s Ward', 0, 0, 0, b'0', ';', '<consumable>Click to Consume:</consumable> Places an invisible ward that reveals the surrounding area for 60 seconds.', '', 1),
	(2051, 'Guardian\'s Horn', 380, 950, 950, b'1', 'Golden Arm of Kobe;Golden Bicep of Kobe;Horn; Horn of the ManWolf; ManWolf', '<stats>+150 Health</stats><br><br><passive>Passive: </passive>Restores 20 Health every 5 seconds.<br><unique>UNIQUE Passive:</unique> Blocks 12 damage from attacks and spells from champions (25% effectiveness vs. damage over time abilities).<br><br><groupLimit>Limited to 1 Guardian\'s Item.</groupLimit>', 'Good starting item for tanks', 1),
	(2052, 'Poro-Snax', 0, 0, 0, b'0', ';', 'This savory blend of free-range, grass-fed Avarosan game hens and organic, non-ZMO Freljordian herbs contains the essential nutrients necessary to keep your Poro purring with pleasure.<br><br><i>All proceeds will be donated towards fighting Noxian animal cruelty.</i>', '', 1),
	(2053, 'Raptor Cloak', 630, 900, 450, b'1', ';', '<stats>+30 Armor<br>+125% Base Health Regen </stats><br><br><unique>UNIQUE Passive - Point Runner:</unique> Builds up to +20% Movement Speed over 2 seconds while near turrets, fallen turrets and Void Gates.', 'Enhances Movement Speed near turrets', 2),
	(2054, 'Diet Poro-Snax', 0, 0, 0, b'0', '', 'All the flavor of regular Poro-Snax, without the calories! Keeps your Poro happy AND healthy.<br><br><consumable>Click to Consume:</consumable> Gives your Poros a delicious healthy treat.', '', 1),
	(2055, 'Control Ward', 30, 75, 75, b'1', 'orange;', '<groupLimit>Can only carry 2 Control Wards in inventory.</groupLimit><br><br><consumable>Click to Consume:</consumable> Places a ward that grants vision of the surrounding area. This device will also reveal invisible traps and reveal / disable wards. Control Wards do not disable other Control Wards. Camouflaged units will also be revealed. <br><br>Limit 1 <font color=\'#BBFFFF\'>Control Ward</font> on the map per player.', 'Used to disable wards and invisible traps in an area.', 1),
	(2056, 'Pilfered Stealth Ward', 24, 60, 60, b'0', 'green;', '<groupLimit>Can only carry 3 Stealth Wards in inventory.</groupLimit><br><br><consumable>Click to Consume:</consumable> Place an invisible <font color=\'#BBFFFF\'>Stealth Ward</font> which reveals the surrounding area for <scaleLevel>60 - 120</scaleLevel> seconds.', 'Use to temporarily provide vision in an area', 1),
	(2057, 'Peering Farsight Ward', 24, 60, 60, b'0', 'blue; totem;', '<consumable>Click to Consume:</consumable> Reveals an area and places a visible fragile ward up to 2000 units away. This ward is untargetable by allies.', 'Grants increased range and reveals the targetted area', 1),
	(2058, 'Travel Size Elixir of Iron', 32, 80, 80, b'0', ';white', '<consumable>Click to Consume:</consumable> Grants +150 Health, 25% Tenacity, increased champion size, and <font color=\'#FF8811\'><u>Path of Iron</u></font> for 45 to 90 seconds, based on level.<br><br><font color=\'#FF8811\'><u>Path of Iron:</u></font> Moving leaves a path behind that boosts allied champion\'s Movement Speed by 15%.<br><br><rules>(Travel Size Elixirs may stack with one another.)</rules>', 'Temporarily increases defenses. Leaves a trail for allies to follow.', 1),
	(2059, 'Travel Size Elixir of Sorcery', 32, 80, 80, b'0', ';blue', '<consumable>Click to Consume:</consumable> Grants +25 Ability Power, 7.5 bonus Mana Regen per 5 seconds and <font color=\'#FF8811\'><u>Sorcery</u></font> for 45 to 90 seconds, based on level. <br><br><font color=\'#FF8811\'><u>Sorcery:</u></font> Damaging a champion or turret deals 15 bonus True Damage. This effect has a 5 second cooldown versus champions but no cooldown versus turrets.<br><br><rules>(Travel Size Elixirs may stack with one another.)</rules><br>', 'Temporarily grants Ability Power and Bonus Damage to champions and turrets.', 1),
	(2060, 'Travel Size Elixir of Wrath', 32, 80, 80, b'0', ';red', '<consumable>Click to Consume:</consumable> Grants +15 Attack Damage and <font color=\'#FF8811\'><u>Bloodlust</u></font> for 45 to 90 seconds, based on level.<br><br><font color=\'#FF8811\'><u>Bloodlust:</u></font> Dealing physical damage to champions heals for 10% of the damage dealt.<br><br><rules>(Travel Size Elixirs may stack with one another.)</rules>', 'Temporarily grants Attack Damage and heals you when dealing physical damage to champions.', 1),
	(2061, 'Pilfered Health Potion', 16, 40, 40, b'0', ';', '<consumable>Click to Consume:</consumable> Restores 50 Health over 5 seconds.', 'Consume to restore Health over time', 1),
	(2062, 'Pilfered Potion of Rouge', 32, 80, 80, b'0', ';', '<consumable>Click to Consume:</consumable> Grants 10 (+1/Level) Adaptive Force for 45 seconds. ', 'Consume to gain a short window of power.', 1),
	(2065, 'Shurelya\'s Reverie', 1575, 2250, 475, b'1', ';shurelya;reverie;', '<stats>+40 Ability Power<br>+200 Health<br><mana>+100% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive:</unique> +10% Cooldown Reduction<br><unique>UNIQUE Passive:</unique> +5% Movement Speed<br><active>UNIQUE Active:</active> Grants yourself and nearby allies +40% Movement Speed for 3 seconds. (90 second cooldown).', 'Grants Health, Ability Power, Mana Regeneration, Cooldown Reduction, and Movement Speed. Activate to speed up nearby allies.', 3),
	(2138, 'Elixir of Iron', 200, 500, 500, b'1', ';white', '<stats><levelLimit>Level 9 required to purchase.</levelLimit></stats><br><br><consumable>Click to Consume:</consumable> Grants +300 Health, 25% Tenacity, increased champion size, and <font color=\'#FF8811\'><u>Path of Iron</u></font> for 3 minutes.<br><br><font color=\'#FF8811\'><u>Path of Iron:</u></font> Moving leaves a path behind that boosts allied champion\'s Movement Speed by 15%.<br><br><rules>(Only one Elixir effect may be active at a time.)</rules>', 'Temporarily increases defenses. Leaves a trail for allies to follow.', 1),
	(2139, 'Elixir of Sorcery', 200, 500, 500, b'1', ';blue', '<stats><levelLimit>Level 9 required to purchase.</levelLimit></stats><br><br><consumable>Click to Consume:</consumable> Grants +50 Ability Power, 15 bonus Mana Regen per 5 seconds and <font color=\'#FF8811\'><u>Sorcery</u></font> for 3 minutes. <br><br><font color=\'#FF8811\'><u>Sorcery:</u></font> Damaging a champion or turret deals 25 bonus True Damage. This effect has a 5 second cooldown versus champions but no cooldown versus turrets.<br><br><rules>(Only one Elixir effect may be active at a time.)</rules><br>', 'Temporarily grants Ability Power and Bonus Damage to champions and turrets.', 1),
	(2140, 'Elixir of Wrath', 200, 500, 500, b'1', ';red', '<stats><levelLimit>Level 9 required to purchase.</levelLimit></stats><br><br><consumable>Click to Consume:</consumable> Grants +30 Attack Damage and <font color=\'#FF8811\'><u>Bloodlust</u></font> for 3 minutes.<br><br><font color=\'#FF8811\'><u>Bloodlust:</u></font> Dealing physical damage to champions heals for 15% of the damage dealt.<br><br><rules>(Only one Elixir effect may be active at a time.)</rules>', 'Temporarily grants Attack Damage and heals you when dealing physical damage to champions.', 1),
	(2319, 'Sly Sack of Gold', 65, 65, 65, b'0', 'BodyBlocking Body Block', '<mainText><font color=\'#FF9900\'>Click to Consume:</font> Contains 40-110 gold.<br><br>Can be sold for @Value@ gold.</mainText>', 'Filled with gold', 1),
	(2403, 'Minion Dematerializer', 0, 0, 0, b'0', ';', '<consumable>Click to Consume:</consumable> Kill target Lane Minion (550 Range, 10 Second Cooldown).', '', 1),
	(2419, 'Commencing Stopwatch', 0, 0, 0, b'0', '', 'Transforms into a Stopwatch after 10 minutes. That Stopwatch contributes 250 gold for the items it builds into.<br><br><rules>(Stopwatch normally contributes 600 gold)</rules>', '', 1),
	(2420, 'Stopwatch', 240, 600, 600, b'1', ';zhg;zonyas', '<active>UNIQUE Active - Stasis:</active> Champion becomes invulnerable and untargetable for 2.5 seconds, but is unable to move, attack, cast spells, or use items during this time (One time use).', 'Activate to become invincible but unable to take actions', 1),
	(2421, 'Broken Stopwatch', 240, 600, 600, b'1', ';', '<unique>UNIQUE Passive:</unique> Is broken, but can still be upgraded.<br><br><rules>After breaking one Stopwatch, the shopkeeper will only sell you Broken Stopwatches.</rules>', 'Upgrades to stopwatch', 1),
	(2422, 'Slightly Magical Boots', 210, 300, 300, b'0', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><unique>UNIQUE Passive - Enhanced Movement:</unique> +25 Movement Speed<br><br><unique>UNIQUE Passive:</unique> +10 Movement Speed<br><br>Boots that build from Slightly Magical Boots retains the +10 Movement Speed.', 'Slightly increases Movement Speed', 1),
	(2423, 'Stopwatch', 240, 600, 600, b'0', '', '<active>UNIQUE Active - Stasis:</active> Champion becomes invulnerable and untargetable for 2.5 seconds, but is unable to move, attack, cast spells, or use items during this time (One time use).', '', 1),
	(2424, 'Broken Stopwatch', 240, 600, 600, b'0', '', '<unique>UNIQUE Passive:</unique> Is broken, but can still be upgraded.<br><br><rules>After breaking one Stopwatch, the shopkeeper will only sell you Broken Stopwatches.</rules>', '', 1),
	(3001, 'Abyssal Mask', 2100, 3000, 1180, b'1', ';', '<stats>+350 Health<br><mana>+300 Mana</mana><br>+55 Magic Resist<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Eternity:</unique> 15% of damage taken from champions is gained as Mana. Spending Mana restores 20% of the cost as Health, up to 25 per spell cast.<br><aura>UNIQUE Aura:</aura> Nearby enemy champions take 15% more magic damage.', 'Nearby enemies take more magic damage', 3),
	(3003, 'Archangel\'s Staff', 2240, 3200, 1050, b'1', ';aa', '<stats>+50 Ability Power<br><mana>+650 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><mana><unique>UNIQUE Passive - Awe:</unique> Grants Ability Power equal to 1% of maximum Mana. Refunds 25% of Mana spent.<br><unique>UNIQUE Passive - Mana Charge:</unique> Grants +8 maximum Mana (max +750 Mana) for each Mana expenditure (occurs up to 3 times every 12 seconds).<br><br>Transforms into Seraph\'s Embrace at +750 Mana.</mana>', 'Increases Ability Power based on maximum Mana', 3),
	(3004, 'Manamune', 1680, 2400, 675, b'1', ';', '<stats>+25 Attack Damage<br><mana>+250 Mana</mana></stats><br><br><mana><unique>UNIQUE Passive - Awe:</unique> Grants bonus Attack Damage equal to 2% of maximum Mana. Refunds 15% of Mana spent.<br><unique>UNIQUE Passive - Mana Charge:</unique> Grants +5 maximum Mana (max +750 Mana) for each basic attack or Mana expenditure (occurs up to 3 times every 12 seconds).<br><br>Transforms into Muramana at +750 Mana.</mana>', 'Increases Attack Damage based on maximum Mana', 3),
	(3005, 'Atma\'s Reckoning', 2030, 2900, 925, b'1', ';wreckoning;Wreckoning', '<stats>+25 Attack Damage<br>+30 Armor<br>+30 Magic Resist</stats><br><br><unique>UNIQUE Passive:</unique> For each second in combat with enemy champions, turrets, or epic monsters, gain Attack Damage equal to 0.5% of maximum health , up to 2.5% .', 'Increases Attack Damage based on maximum Health', 3),
	(3006, 'Berserker\'s Greaves', 770, 1100, 500, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><stats> +35% Attack Speed</stats><br><br><unique>UNIQUE Passive - Enhanced Movement:</unique> +45 Movement Speed', 'Enhances Movement Speed and Attack Speed', 2),
	(3007, 'Archangel\'s Staff (Quick Charge)', 2240, 3200, 1050, b'1', ';aa', '<stats>+50 Ability Power<br><mana>+650 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><mana><unique>UNIQUE Passive - Awe:</unique> Grants Ability Power equal to 1% of maximum Mana. Refunds 25% of Mana spent. <br><unique>UNIQUE Passive - Mana Charge:</unique> Grants +12 maximum Mana (max +750 Mana) for each Mana expenditure (occurs up to 3 times every 12 seconds).<br><br>Transforms into Seraph\'s Embrace at +750 Mana.</mana>', 'Increases Ability Power based on maximum Mana', 3),
	(3008, 'Manamune (Quick Charge)', 1680, 2400, 675, b'1', ';', '<stats>+25 Attack Damage<br><mana>+250 Mana</mana></stats><br><br><mana><unique>UNIQUE Passive - Awe:</unique> Grants bonus Attack Damage equal to 2% of maximum Mana. Refunds 15% of Mana spent.<br><unique>UNIQUE Passive - Mana Charge:</unique> Grants +6 maximum Mana (max +750 Mana) for each basic attack or Mana expenditure (occurs up to 3 times every 12 seconds).<br><br>Transforms into Muramana at +750 Mana.</mana>', 'Increases Attack Damage based on maximum Mana', 3),
	(3009, 'Boots of Swiftness', 630, 900, 600, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><unique>UNIQUE Passive - Enhanced Movement:</unique> +55 Movement Speed<br><unique>UNIQUE Passive - Slow Resist:</unique> Movement slowing effects are reduced by 25%.', 'Enhances Movement Speed and reduces the effect of slows', 2),
	(3010, 'Catalyst of Aeons', 770, 1100, 350, b'1', ';', '<stats>+225 Health<br><mana>+300 Mana</mana></stats><br><br><unique>UNIQUE Passive - Eternity:</unique> 15% of damage taken from champions is gained as Mana. <br><br>Spending Mana restores 20% of the cost as Health, up to 15 per spell cast.  <br><br><rules>(Toggled Spells heal for a maximum of 15 per second.)</rules>', 'Spend Mana to recover Health', 2),
	(3020, 'Sorcerer\'s Shoes', 770, 1100, 800, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><stats>+18 <a href=\'FlatMagicPen\'>Magic Penetration</a></stats><br><br><unique>UNIQUE Passive - Enhanced Movement:</unique> +45 Movement Speed', 'Enhances Movement Speed and magic damage', 2),
	(3022, 'Frozen Mallet', 2170, 3100, 900, b'1', ';fm', '<stats>+700 Health<br>+30 Attack Damage</stats><br><br><unique>UNIQUE Passive - Icy:</unique> Basic attacks slow the target\'s Movement Speed for 1.5 seconds on hit (40% slow for melee attacks, 20% slow for ranged attacks).', 'Basic attacks slow enemies', 3),
	(3024, 'Glacial Shroud', 630, 900, 250, b'1', ';', '<stats>+20 Armor<br><mana>+250 Mana</mana></stats><br><br><unique>UNIQUE Passive:</unique> +10% Cooldown Reduction', 'Increases Armor and Cooldown Reduction', 2),
	(3025, 'Iceborn Gauntlet', 1890, 2700, 750, b'1', ';frozen fist', '<stats>+65 Armor<br>+20% Cooldown Reduction<br><mana>+500 Mana</mana></stats><br><br><unique>UNIQUE Passive - Spellblade:</unique> After using an ability, the next basic attack deals bonus physical damage equal to 100% of base Attack Damage in an area and creates an icy zone for 2 seconds that slows Movement Speed by 30% (1.5 second cooldown).<br><br>Size of zone increases with bonus armor.', 'Basic attacks create a slow field after spell cast', 3),
	(3026, 'Guardian Angel', 1120, 2800, 100, b'1', ';ga', '<stats>+45 Attack Damage<br>+40 Armor</stats><br><br><unique>UNIQUE Passive:</unique> Upon taking lethal damage, restores 50% of base Health and 30% of maximum Mana after 4 seconds of stasis (300 second cooldown).', 'Periodically revives champion upon death', 3),
	(3027, 'Rod of Ages', 1890, 2700, 750, b'1', ';roa', '<stats>+300 Health<br><mana>+300 Mana</mana><br>+60 Ability Power</stats><br><br><passive>Passive:</passive> Grants +20 Health, +10 Mana, and +4 Ability Power per stack (max +200 Health, +100 Mana, and +40 Ability Power). Grants 1 stack per minute (max 10 stacks).<br><unique>UNIQUE Passive - Eternity:</unique> 15% of damage taken from champions is gained as Mana. Spending Mana restores 20% of the cost as Health, up to 25 per spell cast.', 'Greatly increases Health, Mana, and Ability Power', 3),
	(3028, 'Chalice of Harmony', 560, 800, 100, b'1', ';', '<stats>+30 Magic Resist<br><mana>+50% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive - Harmony:</unique> Grants bonus % Base Health Regen equal to your bonus % Base Mana Regen.</unique>', 'Increases Mana and Health Regeneration', 2),
	(3029, 'Rod of Ages (Quick Charge)', 1890, 2700, 750, b'1', ';roa', '<stats>+300 Health<br><mana>+300 Mana</mana><br>+60 Ability Power</stats><br><br><passive>Passive:</passive> Grants +20 Health, +10 Mana, and +4 Ability Power per stack (max +200 Health, +100 Mana, and +40 Ability Power). Grants 1 stack per 40 seconds (max 10 stacks).<br><unique>UNIQUE Passive - Eternity:</unique> 15% of damage taken from champions is gained as Mana. Spending Mana restores 20% of the cost as Health, up to 25 per spell cast.', 'Greatly increases Health, Mana, and Ability Power', 3),
	(3030, 'Hextech GLP-800', 1960, 2800, 450, b'1', 'frost cannon;', '<stats>+80 Ability Power<br><mana>+600 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><unique>UNIQUE Active - Frost Bolt:</unique> Fires a spray of icy bolts that explode on first unit hit, dealing <scaleLevel>100 - 200</scaleLevel> (+20% of your Ability Power) magic damage to all enemies hit. (40 second cooldown, shared with other <font color=\'#9999FF\'><a href=\'itembolt\'>Hextech</a></font> items).<br><br> Enemies hit are slowed by 65% decaying over 2 second.', 'Activate to fire icy bolts to slow enemies', 3),
	(3031, 'Infinity Edge', 2380, 3400, 1225, b'1', ';ie', '<stats>+70 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> Doubles your critical strike chance.<br><unique>UNIQUE Passive:</unique> 10% of critical strike damage dealt to champions is converted to True Damage.', 'Massively enhances critical strikes', 2),
	(3033, 'Mortal Reminder', 1960, 2800, 700, b'1', ';lw;grievous', '<stats>+40 Attack Damage</stats><br><br><unique>UNIQUE Passive - Last Whisper:</unique> +25% <a href=\'FlatArmorPen\'>Armor Penetration</a><br><unique>UNIQUE Passive - Executioner:</unique> Physical damage inflicts <a href=\'GrievousWounds\'>Grievous Wounds</a> on enemy champions for 5 seconds.', 'Overcomes enemies with high Health recovery and Armor', 3),
	(3035, 'Last Whisper', 910, 1300, 950, b'1', ';lw', '<stats>+10 Attack Damage</stats><br><br><unique>UNIQUE Passive - Last Whisper:</unique> +10% <a href=\'FlatArmorPen\'>Armor Penetration</a>', 'Overcomes enemies with high Armor', 2),
	(3036, 'Lord Dominik\'s Regards', 1960, 2800, 625, b'1', ';lw', '<stats>+40 Attack Damage</stats><br><br><unique>UNIQUE Passive - Last Whisper:</unique> +35% <a href=\'FlatArmorPen\'>Armor Penetration</a>', 'Overcomes enemies with high health and armor', 3),
	(3040, 'Seraph\'s Embrace', 2240, 3200, 3200, b'0', ';', '<stats>+50 Ability Power<br><mana>+1400 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><mana><unique>UNIQUE Passive - Awe:</unique> Grants Ability Power equal to 3% of maximum Mana. Refunds 25% of Mana spent.</mana><br><active>UNIQUE Active - Mana Shield:</active> Consumes 15% of current Mana to grant a shield for 2 seconds that absorbs damage equal to 150 plus the amount of Mana consumed (120 second cooldown).', '', 1),
	(3041, 'Mejai\'s Soulstealer', 980, 1400, 1050, b'1', ';', '<stats>+20 Ability Power<br><mana>+200 Mana</mana></stats><br><br><unique>UNIQUE Passive - Dread:</unique> Grants +5 Ability Power per Glory. Grants 10% Movement Speed if you have at least 10 Glory.<br><unique>UNIQUE Passive - Do or Die:</unique> Grants 4 Glory for a champion kill or 2 Glory for an assist, up to 25 Glory total. Lose 10 stacks of Glory upon dying.', 'Grants Ability Power for kills and assists', 2),
	(3042, 'Muramana', 1680, 2400, 2400, b'0', ';', '<stats>+25 Attack Damage<br><mana>+1000 Mana</mana></stats><br><br><mana><unique>UNIQUE Passive - Awe:</unique> Grants bonus Attack Damage equal to 2% of maximum Mana. Refunds 15% of Mana spent.</mana><br><mana><unique>UNIQUE Passive - Shock:</unique> Single target spells and attacks (on hit) on <font color=\'#FFFFFF\'>Champions</font> consume 3% of current Mana to deal bonus physical damage equal to twice the amount of Mana consumed.<br><br>This effect only activates while you have greater than 20% maximum Mana.</mana>', '', 1),
	(3043, 'Muramana', 1680, 2400, 2400, b'0', '', '<stats>+25 Attack Damage<br><mana>+1000 Mana</mana></stats><br><br><mana><unique>UNIQUE Passive - Awe:</unique> Grants bonus Attack Damage equal to 2% of maximum Mana. Refunds 15% of Mana spent.</mana><br><mana><unique>UNIQUE Passive - Shock:</unique> Single target spells and attacks (on hit) on <font color=\'#FFFFFF\'>Champions</font> consume 3% of current Mana to deal bonus physical damage equal to twice the amount of Mana consumed.<br><br>This effect only activates while you have greater than 20% maximum Mana.</mana>', '', 1),
	(3044, 'Phage', 875, 1250, 500, b'1', ';', '<stats>+200 Health<br>+15 Attack Damage</stats><br><br><unique>UNIQUE Passive - Rage:</unique> Basic attacks grant 20 Movement Speed for 2 seconds. Kills grant 60 Movement Speed instead. This Movement Speed bonus is halved for ranged champions.', 'Attacks and kills give a small burst of speed', 2),
	(3046, 'Phantom Dancer', 1890, 2700, 800, b'1', ';pd', '<stats>+45% Attack Speed<br>+30% Critical Strike Chance<br>+5% Movement Speed</stats><br><br><unique>UNIQUE Passive - Spectral Waltz:</unique> While within 550 units of an enemy champion you can see, +7% Movement Speed and you can move through units.<br><unique>UNIQUE Passive - Lament:</unique> The last champion hit deals 12% less damage to you (ends after 10 seconds of not hitting).', 'Move faster near enemies and reduce incoming damage', 3),
	(3047, 'Ninja Tabi', 770, 1100, 500, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><stats>+20 Armor</stats><br><br><unique>UNIQUE Passive:</unique> Blocks 12% of the damage from basic attacks.<br><unique>UNIQUE Passive - Enhanced Movement:</unique> +45 Movement Speed', 'Enhances Movement Speed and reduces incoming basic attack damage', 2),
	(3048, 'Seraph\'s Embrace', 2240, 3200, 3200, b'0', '', '<stats>+50 Ability Power<br><mana>+1400 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><mana><unique>UNIQUE Passive - Awe:</unique> Grants Ability Power equal to 3% of maximum Mana. Refunds 25% of Mana spent.</mana><br><active>UNIQUE Active - Mana Shield:</active> Consumes 15% of current Mana to grant a shield for 2 seconds that absorbs damage equal to 150 plus the amount of Mana consumed (120 second cooldown).', '', 1),
	(3050, 'Zeke\'s Convergence', 1575, 2250, 250, b'1', ';haroldandkumar', '<stats>+60 Armor<br>+30 Magic Resist<br><mana>+250 Mana</mana><br>+10% Cooldown Reduction</stats><br><mainText><active>UNIQUE Active - Conduit:</active> Bind to an ally without an existing Conduit.<br><unique>UNIQUE Passive:</unique> Casting your ultimate near your ally surrounds you with a frost storm and ignites your ally\'s basic attacks for 10 seconds. Enemies inside your frost storm are slowed by 20% and your ally\'s attacks burn their target for 30% bonus magic damage over 2 seconds (45 second cooldown).<br><br><unlockedPassive>Frostfire Covenant:</unlockedPassive> Your frost storm ignites when it slows a burning enemy, dealing 40 magic damage per second and slowing by 40% instead for 3 seconds.</maintext><br><br><rules>(Champions can only be linked by one Zeke\'s Convergence at a time.)</rules>', 'Grants you and your ally bonuses when you cast your ultimate.', 3),
	(3052, 'Jaurim\'s Fist', 840, 1200, 450, b'1', ';enforcer', '<stats>+15 Attack Damage<br>+200 Health</stats><br><br><unique>UNIQUE Passive:</unique> Killing a unit grants 5 maximum Health. This bonus stacks up to 20 times.', 'Attack Damage and stacking Health on Unit Kill', 2),
	(3053, 'Sterak\'s Gage', 2240, 3200, 725, b'1', ';juggernaut;primal', '<stats>+450 Health</stats><br><br><unique>UNIQUE Passive - Giant Strength:</unique> Gain 50% of your Base Attack Damage as Bonus Attack Damage <br><unique>UNIQUE Passive - Lifeline:</unique> Upon taking at least 400 to 1800 damage (based on level) within 5 seconds, gain a shield for 75% of your bonus Health. After 0.75 seconds, the shield decays over 3 seconds (60 second cooldown).<br><br><unlockedPassive>Sterak\'s Fury:</unlockedPassive> When <i>Lifeline</i> triggers, grow in size and strength, gaining +30% Tenacity for 8 seconds.', 'Shields against large bursts of damage', 3),
	(3056, 'Ohmwrecker', 1855, 2650, 950, b'1', ';', '<stats>+300 Health<br>+50 Armor<br>+150% Base Health Regen <br>+10% Cooldown Reduction</stats><br><br><active>UNIQUE Active:</active> Prevents nearby enemy turrets from attacking for 3 seconds (120 second cooldown). This effect cannot be used against the same turret more than once every 8 seconds.<br><br><unique>UNIQUE Passive - Point Runner:</unique> Builds up to +20% Movement Speed over 2 seconds while near turrets (including fallen turrets) and Void Gates.', 'Temporarily disables enemy turrets', 3),
	(3057, 'Sheen', 735, 1050, 700, b'1', ';', '<stats><mana>+250 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Spellblade:</unique> After using an ability, the next basic attack deals bonus physical damage equal to 100% base Attack Damage on hit (1.5 second cooldown).', 'Grants a bonus to next attack after spell cast', 2),
