	(3068, 'Sunfire Cape', 2030, 2900, 800, b'1', ';', '<stats>+425 Health<br>+60 Armor  </stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 25 (+1 per champion level) magic damage per second to nearby enemies. Deals 50% bonus damage to minions and monsters.', 'Constantly deals damage to nearby enemies', 3),
	(3069, 'Remnant of the Ascended', 600, 1500, 250, b'1', ';shurelya;reverie; Eye of Ascension;', '<stats>+200 Health<br>+10 Movement Speed<br>+125% Base Health Regen <br>+10% Cooldown Reduction<br>+2 Gold per 10 seconds</stats><br><br><unique>UNIQUE Passive - Favor: </unique>Enemy minions killed by your allies sometimes drop coins that give either <font color=\'#D4AF37\'>45</font> gold or <font color=\'#44DDFF\'>6%</font> missing mana (minimum 10). Cannon minions always drop coins.<hr><passive>QUEST:</passive> Earn 500 gold using this item.<br><passive>REWARD:</passive> Gain <active>UNIQUE Active - Warding:</active> Consumes a charge to place a <font color=\'#BBFFFF\'>Stealth Ward</font> that reveals the surrounding area for 150 seconds.  Holds up to 4 charges which refill upon visiting the shop.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br><rules><font color=\'#447777\'>\'\'Praise the sun.\'\' - Historian Shurelya, 22 September, 25 CLE</font></rules>', 'Provides Gold, Mana, and Stealth Wards over time', 3),
	(3070, 'Tear of the Goddess', 595, 850, 375, b'1', ';', '<stats><mana>+250 Mana</mana></stats><br><br><mana><unique>UNIQUE Passive - Awe:</unique> Refunds 10% of Mana spent.<br><unique>UNIQUE Passive - Mana Charge:</unique> Grants 4 maximum Mana on Mana expenditure (up to 3 times per 12 seconds).<br><br>Caps at +750 Mana.</mana>', 'Increases maximum Mana as Mana is spent', 2),
	(3071, 'The Black Cleaver', 2100, 3000, 950, b'1', ';bc', '<stats>+400 Health<br>+40 Attack Damage<br>+20% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> Dealing physical damage to an enemy champion Cleaves them, reducing their Armor by 4% for 6 seconds (stacks up to 6 times, up to 24%).<br><unique>UNIQUE Passive - Rage:</unique> Dealing physical damage grants 20 movement speed for 2 seconds. Assists on Cleaved enemy champions or kills on any unit grant 60 movement speed for 2 seconds instead. This Movement Speed is halved for ranged champions.', 'Dealing physical damage to enemy champions reduces their Armor', 3),
	(3072, 'The Bloodthirster', 2450, 3500, 950, b'1', ';bt', '<stats>+80 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> +20% Life Steal<br><unique>UNIQUE Passive:</unique> Your basic attacks can now overheal you. Excess life is stored as a shield that can block 50-350 damage, based on champion level.<br><br>This shield decays slowly if you haven\'t dealt or taken damage in the last 25 seconds.', 'Grants Attack Damage, Life Steal and Life Steal now overheals', 3),
	(3073, 'Tear of the Goddess (Quick Charge)', 595, 850, 375, b'1', ';', '<stats><mana>+250 Mana</mana></stats><br><br><mana><unique>UNIQUE Passive - Awe:</unique> Refunds 10% of Mana spent.<br><unique>UNIQUE Passive - Mana Charge:</unique> Grants 6 maximum Mana on Mana expenditure (up to 3 times per 12 seconds).<br><br>Caps at +750 Mana.</mana>', 'Increases maximum Mana as Mana is spent', 2),
	(3074, 'Ravenous Hydra', 2450, 3500, 400, b'1', ';', '<stats>+80 Attack Damage<br>+100% Base Health Regen <br>+12% Life Steal</stats><br><br><passive>Passive:</passive> 50% of total Life Steal applies to damage dealt by this item.<br><unique>UNIQUE Passive - Cleave:</unique> Basic attacks deal 20% to 60% of total Attack Damage as bonus physical damage to enemies near the target on hit (enemies closest to the target take the most damage).<br><active>UNIQUE Active - Crescent:</active> Deals 60% to 100% of total Attack Damage as physical damage to nearby enemy units (closest enemies take the most damage) (10 second cooldown).', 'Melee attacks hit nearby enemies, dealing damage and restoring Health', 3),
	(3075, 'Thornmail', 2030, 2900, 500, b'1', ';grievous', '<stats>+250 Health<br>+80 Armor</stats><br><br><unique>UNIQUE Passive - Thorns:</unique> Upon being hit by a basic attack, reflects magic damage equal to 10% of your bonus Armor plus 25, inflicting <a href=\'GrievousWounds\'>Grievous Wounds</a> on the attacker for 1 second.<br><unique>UNIQUE Passive - Cold Steel:</unique> When hit by basic attacks, reduces the attacker\'s Attack Speed by 15% for 1 second.', 'Returns damage taken from basic attacks as magic damage', 3),
	(3076, 'Bramble Vest', 700, 1000, 400, b'1', ';grievous', '<stats>+35 Armor</stats><br><br><unique>UNIQUE Passive - Thorns:</unique> Upon being hit by a basic attack, reflects magic damage equal to 3 plus 10% of your bonus Armor, inflicting <a href=\'GrievousWounds\'>Grievous Wounds</a> on the attacker for 1 second.', 'Prevents enemies from using Life Steal against you.', 2),
	(3077, 'Tiamat', 928, 1325, 475, b'1', ';', '<stats>+25 Attack Damage<br>+50% Base Health Regen </stats><br><br><unique>UNIQUE Passive - Cleave:</unique> Basic attacks deal 20% to 60% of total Attack Damage as bonus physical damage to enemies near the target on hit (enemies closest to the target take the most damage).<br><active>UNIQUE Active - Crescent:</active> Deals 60% to 100% of total Attack Damage as physical damage to nearby enemy units (enemies closest to the target take the most damage) (10 second cooldown).', 'Melee attacks hit nearby enemies', 2),
	(3078, 'Trinity Force', 2613, 3733, 333, b'1', ';triforce;tons of damage', '<stats>+250 Health<br><mana>+250 Mana</mana><br>+25 Attack Damage<br>+40% Attack Speed<br>+20% Cooldown Reduction<br>+5% Movement Speed</stats><br><br><unique>UNIQUE Passive - Rage:</unique> Basic attacks grant 20 Movement Speed for 2 seconds. Kills grant 60 Movement Speed instead. This Movement Speed bonus is halved for ranged champions.<br><unique>UNIQUE Passive - Spellblade:</unique> After using an ability, the next basic attack deals bonus physical damage equal to 200% of base Attack Damage on hit (1.5 second cooldown).', 'Tons of Damage', 3),
