	(3086, 'Zeal', 910, 1300, 600, b'1', ';', '<stats>+15% Attack Speed<br>+15% Critical Strike Chance</stats><br><br><unique>UNIQUE Passive:</unique> +5% Movement Speed', 'Slight bonuses to Critical Strike Chance, Movement Speed and Attack Speed', 2),
