	(3124, 'Guinsoo\'s Rageblade', 2170, 3100, 790, b'1', ';', '<stats>+25 Attack Damage<br>+25 Ability Power<br>+25% Attack Speed</stats><br><br><passive>Passive: </passive>Basic attacks deal 15 magic damage on hit.<br><unique>UNIQUE Passive - Last Whisper:</unique> Gain 6 (+0.5 per champion level)% <a href=\'FlatArmorPen\'>Armor Penetration</a>.<br><unique>UNIQUE Passive - Dissolve:</unique> Gain 6 (+0.5 per champion level)% <a href=\'TotalMagicPen\'>Magic Penetration</a>.<br><unique>UNIQUE Passive:</unique> Basic attacks grant +8% Attack Speed for 5 seconds (up to 6 stacks). At max stacks, gain <unlockedPassive>Guinsoo\'s Rage</unlockedPassive>.<br><br><unlockedPassive>Guinsoo\'s Rage:</unlockedPassive> Every other basic attack triggers on hit effects twice.<br><br><rules><font color=\'#8c8c8c\'>While at half stacks, melee champions\' next attack will fully stack Rageblade.</font></rules>', 'Increases Attack Speed, Armor Penetration, and Magic Penetration', 3),
