	(3131, 'Sword of the Divine', 1750, 2500, 800, b'1', ';sotd;lethality', '<stats>+25 Attack Damage<br>+25% Attack Speed</stats><br><br><unique>UNIQUE Passive:</unique> +18 <a href=\'Lethality\'>Lethality</a><br><active>UNIQUE Active:</active> Grants +100% Attack Speed and 100% Critical Strike Chance for 3 seconds or 3 critical strikes (90 second cooldown).', 'Activate to gain 100% Critical Strike Chance for a short duration', 3),
	(3133, 'Caulfield\'s Warhammer', 770, 1100, 400, b'1', ';', '<stats>+25 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> +10% Cooldown Reduction', 'Attack Damage and Cooldown Reduction', 2),
	(3134, 'Serrated Dirk', 770, 1100, 400, b'1', ';lethality', '<stats>+25 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> +10 <a href=\'Lethality\'>Lethality</a><br><unique>UNIQUE Passive - Headhunter:</unique> After killing any enemy, your next damaging spell will deal 40 bonus physical damage (30 second cooldown).', 'Increases Attack Damage and Lethality', 2),
	(3135, 'Void Staff', 1855, 2650, 1365, b'1', ';', '<stats>+70 Ability Power</stats><br><br><unique>UNIQUE Passive - Dissolve:</unique> +40% <a href=\'TotalMagicPen\'>Magic Penetration</a>.', 'Increases magic damage', 2),
	(3136, 'Haunting Guise', 1050, 1500, 665, b'1', ';mask', '<stats>+35 Ability Power<br>+200 Health</stats><br><br><unique>UNIQUE Passive - Madness:</unique> Deal 2% more damage for each second in combat with champions (10% maximum).', 'Increases magic damage', 2),
	(3137, 'Dervish Blade', 1890, 2700, 300, b'1', ';', '<stats>+50% Attack Speed<br>+45 Magic Resist<br>+10% Cooldown Reduction</stats><br><br><active>UNIQUE Active - Quicksilver:</active> Removes all debuffs, and if the champion is melee, also grants +50% bonus Movement Speed for 1 second (90 second cooldown).', 'Activate to remove all debuffs and grant massive Movement Speed', 3),
	(3139, 'Mercurial Scimitar', 2380, 3400, 325, b'1', ';', '<stats>+50 Attack Damage<br>+35 Magic Resist<br>+10% Life Steal</stats><br><br><active>UNIQUE Active - Quicksilver:</active> Removes all crowd control debuffs and also grants +50% bonus Movement Speed for 1 second (90 second cooldown).', 'Activate to remove all crowd control debuffs and grant massive Movement Speed', 3),
	(3140, 'Quicksilver Sash', 910, 1300, 850, b'1', ';qss', '<stats>+30 Magic Resist</stats><br><br><active>UNIQUE Active - Quicksilver:</active> Removes all crowd control debuffs (90 second cooldown).', 'Activate to remove all crowd control debuffs', 2),
	(3142, 'Youmuu\'s Ghostblade', 2030, 2900, 700, b'1', ';lethality', '<stats>+55 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> +18 <a href=\'Lethality\'>Lethality</a><br><unique>UNIQUE Passive:</unique> +40 Movement Speed out of Combat<br><active>UNIQUE Active:</active> Grants +20% Movement Speed for 6 seconds (45 second cooldown).', 'Activate to greatly increase Movement Speed', 3),
	(3143, 'Randuin\'s Omen', 2030, 2900, 900, b'1', ';', '<stats>+400 Health<br>+60 Armor</stats><br><br><unique>UNIQUE Passive:</unique> -20% damage taken from basic attack critical strikes.<br><unique>UNIQUE Passive - Cold Steel:</unique> When hit by basic attacks, reduces the attacker\'s Attack Speed by 15% for 1 second.<br><active>UNIQUE Active:</active> Slows the Movement Speed of nearby enemy units by 55% for 2 seconds (60 second cooldown).', 'Greatly increases defenses, activate to slow nearby enemies', 3),
	(3144, 'Bilgewater Cutlass', 1050, 1500, 250, b'1', ';', '<stats>+25 Attack Damage<br>+10% Life Steal</stats><br><br><active>UNIQUE Active:</active> Deals 100 magic damage and slows the target champion\'s Movement Speed by 25% for 2 seconds (90 second cooldown).', 'Activate to deal magic damage and slow target champion', 3),
	(3145, 'Hextech Revolver', 735, 1050, 180, b'1', ';', '<stats>+40 Ability Power</stats><br><br><unique>UNIQUE Passive - Magic Bolt:</unique> Damaging an enemy champion with a basic attack shocks them for <scaleLevel>50 - 125</scaleLevel> bonus magic damage (40 second cooldown, shared with other <font color=\'#9999FF\'><a href=\'itembolt\'>Hextech</a></font> items).<br><br>Magic Bolt\'s cooldown is reduced by Active Item cooldown reduction.<br><br><rules>(Damage scales based on level. Hextech effects can trigger other item spell effects.)</rules>', 'Increases Ability Power. Deal bonus magic damage on attack periodically.', 2),
	(3146, 'Hextech Gunblade', 2380, 3400, 850, b'1', ';', '<stats>+40 Attack Damage<br>+80 Ability Power</stats><br><br><unique>UNIQUE Passive:</unique> Heal for 15% of damage dealt. This is 33% as effective for Area of Effect damage.<br><active>UNIQUE Active - Lightning Bolt:</active> Deals <scaleLevel>175 - 253</scaleLevel> (+30% of Ability Power) magic damage and slows the target champion\'s Movement Speed by 40% for 2 seconds (40 second cooldown, shared with other <font color=\'#9999FF\'><a href=\'itembolt\'>Hextech</a></font> items).', 'Increases Attack Damage and Ability Power, activate to slow a target', 4),
	(3147, 'Duskblade of Draktharr', 2030, 2900, 700, b'1', ';lethality', '<stats>+55 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> +21 <a href=\'Lethality\'>Lethality</a><br><unique>UNIQUE Passive - Blackout:</unique> When spotted by an enemy ward, reveal traps and disable wards around you for 8 seconds. Melee attacks instantly kill these devices. (90 second cooldown).<br><unique>UNIQUE Passive - Nightstalker:</unique> After being unseen for at least 1 second, your next basic attack against an enemy champion deals <scaleLevel>30 - 150</scaleLevel> bonus physical damage and slows them by 99% for 0.25 seconds. Ranged basic attacks do not apply the slow. (Lasts for 5 seconds after being seen by an enemy champion).', 'Deals additional physical damage when ambushing enemies and provides trap and ward detection periodically', 3),
	(3148, 'Space Hextech Gunblade', 2380, 3400, 850, b'1', ';', '<stats>+40 Attack Damage<br>+80 Ability Power</stats><br><br><unique>UNIQUE Passive:</unique> Heal for 4% of damage dealt. This is 33% as effective for Area of Effect damage.<br><active>UNIQUE Active - Lightning Bolt:</active> Deals <scaleLevel>175 - 253</scaleLevel> (+30% of Ability Power) magic damage and slows the target champion\'s Movement Speed by 40% for 2 seconds (40 second cooldown, shared with other <font color=\'#9999FF\'><a href=\'itembolt\'>Hextech</a></font> items).', 'Increases Attack Damage and Ability Power, activate to slow a target', 4),
	(3149, 'Space Blade of the Ruined King', 2240, 3200, 700, b'1', ';brk;bork;bork;bork;botrk', '<stats>+40 Attack Damage<br>+25% Attack Speed<br>+3% Life Steal</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 8% of the target\'s current Health as bonus physical damage on hit.<br><active>UNIQUE Active:</active> Deals 100 magic damage to target champion and steals 25% of their Movement Speed for 3 seconds (90 second cooldown).<br><br><rules>Minimum bonus physical damage dealt is 15.<br>Maximum bonus physical damage dealt to monsters and minions is 60.<br>User\'s Life Steal is applied to bonus physical damage dealt.</rules>', 'Deals damage based on target\'s Health, can steal Movement Speed', 4),
	(3151, 'Liandry\'s Torment', 2170, 3100, 750, b'1', ';mask', '<stats>+75 Ability Power<br>+300 Health</stats><br><br><unique>UNIQUE Passive - Madness:</unique> Deal 2% more damage for each second in combat with champions (10% maximum).<br><unique>UNIQUE Passive - Torment:</unique> Spells burn enemies for 3 seconds, dealing bonus magic damage equal to 1.5% of their maximum Health per second. Burn damage is increased to 2.5% against <a href=\'MovementImpaired\'>movement-impaired</a> units.', 'Spell damage burns enemies for a portion of their Health', 3),
	(3152, 'Hextech Protobelt-01', 1750, 2500, 650, b'1', 'rocket belt;', '<stats>+300 Health<br>+60 Ability Power<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Active - Fire Bolt:</unique> Dash forward and unleash a nova of fire bolts that deal <scaleLevel>75 - 150</scaleLevel> (+25% of your Ability Power) as magic damage (40 second cooldown, shared with other <font color=\'#9999FF\'><a href=\'itembolt\'>Hextech</a></font> items).<br><br>Champions and Monsters hit by multiple fire bolts take 10% damage per additional bolt.<br><br><rules>(This dash cannot pass through terrain.)</rules>', 'Activate to dash forward and unleash a fiery explosion', 3),
	(3153, 'Blade of the Ruined King', 2240, 3200, 700, b'1', ';brk;bork;bork;bork;botrk', '<stats>+40 Attack Damage<br>+25% Attack Speed<br>+12% Life Steal</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 8% of the target\'s current Health as bonus physical damage on hit.<br><active>UNIQUE Active:</active> Deals 100 magic damage to target champion and steals 25% of their Movement Speed for 3 seconds (90 second cooldown).<br><br><rules>Minimum bonus physical damage dealt is 15.<br>Maximum bonus physical damage dealt to monsters and minions is 60.<br>User\'s Life Steal is applied to bonus physical damage dealt.</rules>', 'Deals damage based on target\'s Health, can steal Movement Speed', 4),
	(3154, 'Wriggle\'s Lantern', 1155, 1650, 100, b'1', '', '', '', 0),
	(3155, 'Hexdrinker', 910, 1300, 500, b'1', ';', '<stats>+20 Attack Damage<br>+35 Magic Resist</stats><br><br><unique>UNIQUE Passive - Lifeline:</unique> Upon taking magic damage that would reduce Health below 30%, grants a shield that absorbs 110 to 280 (based on level) magic damage for 5 seconds (90 second cooldown).', 'Increases Attack Damage and Magic Resist', 2),
	(3156, 'Maw of Malmortius', 2275, 3250, 850, b'1', ';', '<stats>+50 Attack Damage<br>+50 Magic Resist<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Lifeline:</unique> Upon taking magic damage that would reduce Health below 30%, grants a shield that absorbs up to 350 magic damage within 5 seconds (90 second cooldown).<br><unlockedPassive>Lifegrip:</unlockedPassive> When <i>Lifeline</i> triggers, gain +20 Attack Damage, +10% Spell Vamp and +10% Life Steal until out of combat.', 'Grants bonus Attack Damage when Health is low', 3),
	(3157, 'Zhonya\'s Hourglass', 2030, 2900, 300, b'1', ';zhg;zonyas', '<stats>+75 Ability Power<br>+45 Armor<br>+10% Cooldown Reduction</stats><br><br><active>UNIQUE Active - Stasis:</active> Champion becomes invulnerable and untargetable for 2.5 seconds, but is unable to move, attack, cast spells, or use items during this time (120 second cooldown).', 'Activate to become invincible but unable to take actions', 3),
	(3158, 'Ionian Boots of Lucidity', 630, 900, 600, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><unique>UNIQUE Passive:</unique> +10% Cooldown Reduction<br><unique>UNIQUE Passive - Enhanced Movement:</unique> +45 Movement Speed<br><unique>UNIQUE Passive:</unique> Reduces Summoner Spell cooldowns by 10%<br><br><br><rules><font color=\'#FDD017\'>\'\'This item is dedicated in honor of Ionia\'s victory over Noxus in the Rematch for the Southern Provinces on 10 December, 20 CLE.\'\'</font></rules>', 'Increases Movement Speed and Cooldown Reduction', 2),
	(3161, 'Spear of Shojin', 2030, 2900, 800, b'1', ';', '<stats>+60 Attack Damage<br>+200 Health<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> <a href=\'FlatDamageReduction\'>Reduce damage</a> from champion attacks and abilities by 20 plus 10% of bonus attack damage (maximum 70).<br><unique>UNIQUE Passive:</unique> When near at least 3 enemy champions, land a basic attack to gain <unlockedPassive>Dragon Heart</unlockedPassive> (90s cooldown).<br><br><unlockedPassive>Dragon Heart:</unlockedPassive> Block 200% more damage for 6s, refreshing on takedown.<br><br><rules></rules>', 'Reduce damage taken from champions by a flat amount. Attack while near multiple enemy champions to increase this amount for a short time.', 3),
	(3162, 'Space Bilgewater Cutlass', 1050, 1500, 250, b'1', ';', '<stats>+25 Attack Damage<br>+2.5% Life Steal</stats><br><br><active>UNIQUE Active:</active> Deals 100 magic damage and slows the target champion\'s Movement Speed by 25% for 2 seconds (90 second cooldown).', 'Activate to deal magic damage and slow target champion', 3),
	(3163, 'Space Maw of Malmortius', 2275, 3250, 850, b'1', ';', '<stats>+50 Attack Damage<br>+50 Magic Resist<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Lifeline:</unique> Upon taking magic damage that would reduce Health below 30%, grants a shield that absorbs up to 350 magic damage within 5 seconds (90 second cooldown).<br><unlockedPassive>Lifegrip:</unlockedPassive> When <i>Lifeline</i> triggers, gain +20 Attack Damage, +2.5% Spell Vamp and +2.5% Life Steal until out of combat.', 'Grants bonus Attack Damage when Health is low', 3),
	(3165, 'Morellonomicon', 2100, 3000, 650, b'1', ';nmst;grievous', '<stats>+80 Ability Power<br>+300 Health</stats><br><br><unique>UNIQUE Passive - Touch of Death:</unique> +15 <a href=\'FlatMagicPen\'>Magic Penetration</a><br><unique>UNIQUE Passive - Cursed Strike:</unique> Magic damage dealt to champions inflicts them with <a href=\'GrievousWounds\'>Grievous Wounds</a> for 3 seconds.', 'Increases magic damage', 3),
	(3170, 'Moonflair Spellblade', 1680, 2400, 580, b'1', ';', '<stats>+50 Ability Power<br>+50 Armor<br>+50 Magic Resist</stats><br><br><unique>UNIQUE Passive - Tenacity:</unique> Reduces the duration of stuns, slows, taunts, fears, silences, blinds, polymorphs, and immobilizes by 35%.', 'Improves defense and reduces duration of disabling effects', 3),
	(3172, 'Zephyr', 1960, 2800, 900, b'1', ';', '<stats>+50 Attack Damage<br>+40% Attack Speed<br>+10% Movement Speed</stats><br><br><unique>UNIQUE Passive - Tenacity:</unique> Reduces the duration of stuns, slows, taunts, fears, silences, blinds, polymorphs, and immobilizes by 35%.', 'Mobility and Tenacity', 2),
	(3173, 'Space Boots of Lucidity', 630, 900, 600, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><unique>UNIQUE Passive:</unique> +10% Cooldown Reduction<br><unique>UNIQUE Passive - Enhanced Movement:</unique> +45 Movement Speed<br><br><rules><font color=\'#FDD017\'>\'\'This item is dedicated to space.\'\'</font></rules>', 'Increases Movement Speed and Cooldown Reduction', 2),
	(3174, 'Athene\'s Unholy Grail', 1470, 2100, 400, b'1', ';', '<stats>+30 Ability Power<br>+30 Magic Resist<br>+10% Cooldown Reduction<br><mana>+100% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive:</unique> Gain 35% of the <a href=\'premitigation\'><font color=\'#6666FF\'><u>premitigation</u></font></a> damage dealt to champions as Blood Charges, up to <scaleLevel>100 - 250</scaleLevel> max. Healing or shielding another ally consumes charges equal to 100% of the heal or shield value, healing the ally for that amount.<br><unique>UNIQUE Passive - Dissonance:</unique> Grants 5 ability power per 25% Base Mana Regen you have. Disables <unique>Harmony</unique> on your other items.<br><br><rules>(Maximum amount of Blood Charges stored is based on level. Healing amplification is applied to the total heal value.)</rules>', 'Deal damage to empower your heals and shields', 3),
	(3175, 'Head of Kha\'Zix', 0, 0, 0, b'0', '', '<unique>UNIQUE Active - Bonetooth Totem:</unique> Places a Stealth Ward that lasts 180 seconds (90 Second cooldown). Limit 3 Stealth Wards on the map per player.<br><br><unique>UNIQUE Passive - Mementos of the Hunt:</unique> Rengar collects trophies when killing Champions and gains bonus effects based on how many trophies he has. Kills and assists grant 1 trophy.<br><br><passive>3 Trophies:</passive> Rengar gains 25 Movement Speed whilst out of combat or in brush. <br><passive>6 Trophies:</passive> Increases the range of Rengar\'s Leap by 125.<br><passive>12 Trophies:</passive> Thrill of the Hunt\'s duration is increased by 5 seconds.<br><passive>20 Trophies:</passive> Rengar gains the movement speed bonus of Thrill of the Hunt while he is stealthed.', '', 1),
	(3181, 'Sanguine Blade', 1680, 2400, 625, b'1', ';', '<stats>+45 Attack Damage<br>+10% Life Steal</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks grant +6 Attack Damage and +1% Life Steal for 8 seconds on hit (effect stacks up to 5 times).', 'Greatly increases Attack Damage and Life Steal', 3),
	(3184, 'Guardian\'s Hammer', 380, 950, 950, b'1', ';dblade', '<stats>+150 Health<br>+20 Attack Damage<br>+10% Life Steal</stats><br><br><groupLimit>Limited to 1 Guardian\'s Item.</groupLimit>', 'Good starting item for attackers', 1),
	(3187, 'Arcane Sweeper', 1435, 2050, 350, b'1', ';', '<stats>+225 Health<br>+250 Mana<br>+25 Armor<br>+20% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Trap Detection:</unique> Grants <font color=\'#ee91d7\'>True Sight</font>  of nearby enemy traps.<br><active>UNIQUE Active - Hunter\'s Sight:</active> An arcane mist grants vision in the target area for 5 seconds, revealing enemy champions in the area for 3 seconds (60 second cooldown).', 'Activate to reveal a nearby area of the map', 3),
	(3190, 'Locket of the Iron Solari', 1540, 2200, 650, b'1', ';', '<stats>+30 Armor<br>+60 Magic Resist</stats><br><br><active>UNIQUE Active:</active> Grants a decaying shield to nearby allied champions for 2.5 seconds that absorbs up to 30 (+15 per level) <scaleHealth>(+20% of your bonus health)</scaleHealth> damage (120 second cooldown).<br><br><rules>Shield per level uses the higher of your level or the target\'s level.<br>Shield ratio scales with your level.<br>Shield amount is reduced to 25% if the target has been affected by another Locket of the Iron Solari in the last 20 seconds.</rules>', 'Activate to shield nearby allies from damage', 3),
	(3191, 'Seeker\'s Armguard', 770, 1100, 65, b'1', ';', '<stats>+30 Armor<br>+20 Ability Power</stats><br><br><unique>UNIQUE Passive:</unique> Killing a unit grants 0.5 bonus Armor and Ability Power. This bonus stacks up to 30 times.', 'Increases Armor and Ability Power', 2),
	(3193, 'Gargoyle Stoneplate', 1750, 2500, 380, b'1', ';', '<stats>+40 Armor<br>+40 Magic Resist</stats></stats><br><br><unique>UNIQUE Passive - Stone Skin:</unique> If 3+ enemy champions are nearby, grants 40 bonus Armor and Magic Resist.<br><active>UNIQUE Active - Metallicize:</active> Increases Health by 40% and increases champion size, but reduces damage dealt by 60% for 4 seconds (90 second cooldown). If Stone Skin is active, the Health increase becomes 100% instead.', 'Greatly increases defense near multiple enemies.', 3),
	(3194, 'Adaptive Helm', 1960, 2800, 1000, b'1', ';', '<stats>+350 Health<br>+55 Magic Resist<br>+100% Base Health Regeneration <br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> Taking magic damage from a spell or effect reduces all subsequent magic damage from that same spell or effect by 20% for 4 seconds.', 'Reduces damage from repeated spells and effects.', 3),
	(3196, 'The Hex Core mk-1', 805, 1150, 1150, b'1', ';viktor', '<stats>+3 Ability Power per level<br>+15 Mana per level</stats><br><br><unique>UNIQUE Passive - Progress:</unique> Viktor can upgrade one of his basic spells.', 'Allows Viktor to improve an ability of his choice', 2),
	(3197, 'The Hex Core mk-2', 1505, 2150, 1000, b'1', ';viktor', '<stats>+6 Ability Power per level<br>+20 Mana per level</stats><br><br><unique>UNIQUE Passive - Progress:</unique> Viktor can upgrade one of his basic spells.', 'Allows Viktor to improve an ability of his choice', 3),
	(3198, 'Perfect Hex Core', 2100, 3000, 850, b'1', ';viktor', '<stats>+10 Ability Power per level<br>+25 Mana per level</stats><br><br><unique>UNIQUE Passive - Glorious Evolution:</unique> Viktor has reached the pinnacle of his power, upgrading Chaos Storm in addition to his basic spells.', 'Allows Viktor to improve an ability of his choice', 4),
	(3200, 'Prototype Hex Core', 0, 0, 0, b'0', ';viktor', '<stats>+1 Ability Power per level<br>+10 Mana per level</stats><br><br><unique>UNIQUE Passive - Progress:</unique> This item can be upgraded three times to enhance Viktor\'s basic abilities.', 'Increases Ability Power and can be upgraded to improve Viktor\'s abilities', 1),
	(3211, 'Spectre\'s Cowl', 840, 1200, 350, b'1', ';hat', '<stats>+250 Health<br>+25 Magic Resist</stats><br><br><unique>UNIQUE Passive:</unique> Grants 150% Base Health Regen for up to 10 seconds after taking damage from an enemy champion.', 'Improves defense and grants regeneration upon being damaged', 2),
	(3222, 'Mikael\'s Crucible', 1470, 2100, 500, b'1', ';', '<stats>+40 Magic Resist<br>+10% Cooldown Reduction<br><mana>+100% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive:</unique> +20% Heal and Shield Power<br><unique>UNIQUE Passive - Harmony:</unique> Grants bonus % Base Health Regen equal to your bonus % Base Mana Regen.<br><active>UNIQUE Active:</active> Cleanses all stuns, roots, taunts, fears, silences, and slows on an allied champion and grants them slow immunity for 2 seconds (120 second cooldown). <br><br>Cleansing an effect grants the ally 40% movement speed for 2 seconds.', 'Activate to remove all disabling effects from an allied champion', 3),
	(3230, 'Space Ravenous Hydra', 2450, 3500, 400, b'1', ';', '<stats>+80 Attack Damage<br>+100% Base Health Regen <br>+3% Life Steal</stats><br><br><passive>Passive:</passive> 50% of total Life Steal applies to damage dealt by this item.<br><unique>UNIQUE Passive - Cleave:</unique> Basic attacks deal 20% to 60% of total Attack Damage as bonus physical damage to enemies near the target on hit (enemies closest to the target take the most damage).<br><active>UNIQUE Active - Crescent:</active> Deals 60% to 100% of total Attack Damage as physical damage to nearby enemy units (closest enemies take the most damage) (10 second cooldown).', 'Melee attacks hit nearby enemies, dealing damage and restoring Health', 3),
	(3231, 'Space Mercurial Scimitar', 2380, 3400, 325, b'1', ';', '<stats>+50 Attack Damage<br>+35 Magic Resist<br>+2.5% Life Steal</stats><br><br><active>UNIQUE Active - Quicksilver:</active> Removes all crowd control debuffs and also grants +50% bonus Movement Speed for 1 second (90 second cooldown).', 'Activate to remove all crowd control debuffs and grant massive Movement Speed', 3),
	(3252, 'Poacher\'s Dirk', 350, 500, 150, b'1', '', '', '', 0),
	(3285, 'Luden\'s Echo', 2240, 3200, 1050, b'1', ';', '<stats>+90 Ability Power<br><mana>+600 Mana</mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><unique>UNIQUE Passive - Echo:</unique> Gain charges upon moving or casting. At 100 charges, the next damaging spell hit expends all charges to deal 100 (+10% of Ability Power) bonus magic damage to up to 4 targets on hit.', 'Increases Ability Power, Mana, and Cooldown Reduction', 3),
	(3301, 'Ancient Coin', 160, 400, 400, b'1', ';', '<stats>+5 Movement Speed<br>+5% Cooldown Reduction<br>+2 Gold per 10 seconds</stats><br><br><unique>UNIQUE Passive - Favor:</unique> Enemy minions killed by your allies sometimes drop coins that give either <font color=\'#D4AF37\'>25</font> gold or <font color=\'#44DDFF\'>6%</font> missing mana (minimum 10). Cannon minions always drop coins.<hr><passive>QUEST:</passive> Earn 500 gold using this item and upgrade to <font color=\'#CFBF84\'>Nomad\'s Medallion</font>.<br><passive>REWARD:</passive> Gain <active>UNIQUE Active - Warding:</active> Consumes a charge to place a <font color=\'#BBFFFF\'>Stealth Ward</font> that reveals the surrounding area for 150 seconds.  Holds up to 3 charges which refill upon visiting the shop.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br><i><font color=\'#447777\'>\'\'Gold dust rises from the desert and clings to the coin.\'\' - Historian Shurelya, 11 November, 23 CLE</font></i>', 'Grants gold and mana when nearby minions die that you didn\'t kill', 1),
	(3302, 'Relic Shield', 160, 400, 400, b'1', ';', '<stats>+50 Health<br>+1 Gold per 10 seconds </stats><br><br><unique>UNIQUE Passive - Spoils of War:</unique> Melee basic attacks execute minions below 195 (+5 per level) Health. Killing a minion heals the owner and the nearest allied champion for 15 Health (+2% missing health) and grants them kill Gold. 50% healing if the owner is ranged. These effects require a nearby ally. Recharges every 40 seconds. Max 2 charges.<hr><passive>QUEST:</passive> Earn 500 gold using this item and upgrade to <font color=\'#CFBF84\'>Targon\'s Brace</font>.<br><passive>REWARD:</passive> Gain <active>UNIQUE Active - Warding:</active> Consumes a charge to place a <font color=\'#BBFFFF\'>Stealth Ward</font> that reveals the surrounding area for 150 seconds.  Holds up to 3 charges which refill upon visiting the shop.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Kill minions periodically to heal and grant gold to a nearby ally', 1),
	(3303, 'Spellthief\'s Edge', 160, 400, 400, b'1', ';', '<stats>+10 Ability Power<br>+2 Gold per 10 seconds<br><mana>+25% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive - Tribute:</unique> Damaging spells and attacks against champions or buildings deal 13 additional magic damage and grant 10 Gold per unique spell cast. This can occur up to 3 times every 30 seconds. Before quest completion, killing minions and non-epic monsters slows Tribute and gold generation.<hr><passive>QUEST:</passive> Earn 500 gold using this item and upgrade to <font color=\'#CFBF84\'>Frostfang</font>.<br><passive>REWARD:</passive> Gain <active>UNIQUE Active - Warding:</active> Consumes a charge to place a <font color=\'#BBFFFF\'>Stealth Ward</font> that reveals the surrounding area for 150 seconds.  Holds up to 3 charges which refill upon visiting the shop.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants gold when you damage enemies', 1),
	(3304, 'Timeworn Ancient Coin', 160, 400, 400, b'1', ';', '<stats>+5 Movement Speed<br>+5% Cooldown Reduction<br>+2 Gold per 10 seconds</stats><br><br><unique>UNIQUE Passive - Favor:</unique> Enemy minions killed by your allies sometimes drop coins that give either <font color=\'#D4AF37\'>25</font> gold or <font color=\'#44DDFF\'>6%</font> missing mana (minimum 10). Cannon minions always drop coins.<hr><passive>QUEST:</passive> Earn 750 gold using this item and upgrade to <font color=\'#CFBF84\'>Timeworn Nomad\'s Medallion</font>.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Favor</font> is upgraded to <font color=\'#CFBF84\'><a href=\'coinlinequestreward\'>Emperor\'s Favor</a></font> and allied champions moving toward you gain 8% movement speed.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br><i><font color=\'#447777\'>\'\'Gold dust rises from the desert and clings to the coin.\'\' - Historian Shurelya, 11 November, 23 CLE</font></i>', 'Grants gold and mana when nearby minions die that you didn\'t kill', 1),
	(3305, 'Timeworn Nomad\'s Medallion', 340, 850, 300, b'1', ';', '<stats>+10 Movement Speed<br>+50% Base Health Regen <br>+10% Cooldown Reduction<br>+2 Gold per 10 seconds</stats><br><br><unique>UNIQUE Passive - Favor:</unique> Enemy minions killed by your allies sometimes drop coins that give either <font color=\'#D4AF37\'>45</font> gold or <font color=\'#44DDFF\'>6%</font> missing mana (minimum 10). Cannon minions always drop coins.<hr><passive>QUEST:</passive> Earn 750 gold using this item.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Favor</font> is upgraded to <font color=\'#CFBF84\'><a href=\'coinlinequestreward\'>Emperor\'s Favor</a></font> and allied champions moving toward you gain 8% movement speed.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br><rules><font color=\'#447777\'>\'\'The medallion shines with the glory of a thousand voices when exposed to the sun.\'\' - Historian Shurelya, 22 June, 24 CLE</font></rules>', 'Grants gold and mana when nearby minions die that you didn\'t kill', 2),
	(3306, 'Timeworn Talisman of Ascension', 880, 2200, 450, b'1', ';shurelya;reverie', '<stats>+10 Movement Speed<br>+45 Armor<br>+175% Base Health Regen <br>+10% Cooldown Reduction<br>+2 Gold per 10 seconds</stats><br><br><unique>UNIQUE Passive - Point Runner:</unique> Builds up to +20% Movement Speed over 2 seconds while near turrets, fallen turrets and Void Gates.<br><unique>UNIQUE Passive - Favor: </unique>Enemy minions killed by your allies sometimes drop coins that give either <font color=\'#D4AF37\'>45</font> gold or <font color=\'#44DDFF\'>6%</font> missing mana (minimum 10). Cannon minions always drop coins.<br><active>UNIQUE Active:</active> Grants nearby allies +@Effect5Amount*100@% Movement Speed for @Effect6Amount@ seconds (60 second cooldown).<hr><passive>QUEST:</passive> Earn 750 gold using this item.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Favor</font> is upgraded to <font color=\'#CFBF84\'><a href=\'coinlinequestreward\'>Emperor\'s Favor</a></font> and allied champions moving toward you gain 8% movement speed.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br><rules><font color=\'#447777\'>\'\'Praise the sun.\'\' - Historian Shurelya, 22 September, 25 CLE</font></rules>', 'Increases Health / Mana Regeneration and Cooldown Reduction. Activate to speed up nearby allies.', 3),
	(3307, 'Timeworn Relic Shield', 160, 400, 400, b'1', ';', '<stats>+50 Health<br>+2 Gold per 10 seconds </stats><br><br><unique>UNIQUE Passive - Spoils of War:</unique> Melee basic attacks execute minions below 195 (+5 per level) Health. Killing a minion heals the owner and the nearest allied champion for 15 Health (+2% missing health) and grants them kill Gold. Healing is halved if the owner is ranged. These effects require a nearby ally. Recharges every 40 seconds. Max 2 charges.<hr><passive>QUEST:</passive> Earn 750 gold using this item and upgrade to <font color=\'#CFBF84\'>Timeworn Targon\'s Brace</font>.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Shield Battery</font>, a permanent shield that regenerates slowly outside of combat.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Kill minions periodically to heal and grant gold to a nearby ally', 1),
	(3308, 'Timeworn Targon\'s Brace', 340, 850, 300, b'1', ';', '<stats>+125 Health<br>+50% Base Health Regen <br>+4 Gold per 10 seconds </stats><br><br><unique>UNIQUE Passive - Spoils of War:</unique> Melee basic attacks execute minions below 200 (+10 per level) Health. Killing a minion heals the owner and the nearest allied champion for 40 Health (+2% missing health) and grants them kill Gold. Healing is halved if the owner is ranged. These effects require a nearby ally. Recharges every 30 seconds. Max 3 charges.<hr><passive>QUEST:</passive> Earn 750 gold using this item.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Shield Battery</font>, a permanent shield that regenerates slowly outside of combat.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Periodically kill enemy minions to heal and grant gold to a nearby ally', 2),
	(3309, 'Timeworn Face of the Mountain', 840, 2100, 450, b'1', ';', '<stats>+350 Health<br>+100% Base Health Regen <br>+10% Cooldown Reduction<br>+4 Gold per 10 seconds </stats><br><br><unique>UNIQUE Passive - Spoils of War:</unique> Melee basic attacks execute minions below 320 (+20 per level) Health. Killing a minion heals the owner and the nearest allied champion for 50 Health (+2% missing health) and grants them kill Gold. Healing is halved if the owner is ranged. These effects require a nearby ally. Recharges every 20 seconds. Max 4 charges.<br><unique>UNIQUE Active:</unique> Grant a shield to you and an ally equal to 10% of your maximum Health for 4 seconds. After 4 seconds, the shields explode to slow nearby enemies by 40% for 2 seconds (60 second cooldown).  Automatically targets the most wounded ally if cast upon self.<hr><passive>QUEST:</passive> Earn 750 gold using this item.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Shield Battery</font>, a permanent shield that regenerates slowly outside of combat.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Shield an ally from damage based on your Health', 3),
	(3310, 'Timeworn Spellthief\'s Edge', 160, 400, 400, b'1', ';', '<stats>+10 Ability Power<br>+2 Gold per 10 seconds<br><mana>+25% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive - Tribute:</unique> Damaging spells and attacks against champions or buildings deal 13 additional magic damage and grant 10 Gold per unique spell cast. This can occur up to 3 times every 30 seconds. Before quest completion, killing minions and non-epic monsters slows Tribute and gold generation.<hr><passive>QUEST:</passive> Earn 750 gold using this item and upgrade to <font color=\'#CFBF84\'>Timeworn Frostfang</font>.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Tribute</font> is upgraded into <font color=\'#CFBF84\'><a href=\'frostqueenslinequestreward\'>Queen\'s Tribute</a></font>.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants gold when you damage enemies', 1),
	(3311, 'Timeworn Frostfang', 340, 850, 325, b'1', ';', '<stats>+20 Ability Power<br>+2 Gold per 10 seconds<br><mana>+50% Base Mana Regen </mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Tribute:</unique> Damaging spells and attacks against champions or buildings deal 18 additional magic damage and grant 20 Gold per unique spell cast. This can occur up to 3 times every 30 seconds. Before quest completion, killing minions and non-epic monsters slows Tribute and gold generation.<hr><passive>QUEST:</passive> Earn 750 gold using this item.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Tribute</font> is upgraded into <font color=\'#CFBF84\'><a href=\'frostqueenslinequestreward\'>Queen\'s Tribute</a></font>.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Grants gold when you damage an enemy', 2),
	(3312, 'Timeworn Frost Queen\'s Claim', 880, 2200, 500, b'1', 'spooky ghosts;', '<stats>+60 Ability Power<br>+10% Cooldown Reduction<br>+2 Gold per 10 seconds<br><mana>+50% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive - Tribute:</unique> Damaging spells and attacks against champions or buildings deal 18 additional magic damage and grant 20 Gold per unique spell cast. This can occur up to 3 times every 30 seconds. Before quest completion, killing minions and non-epic monsters slows Tribute and gold generation.<br><active>UNIQUE Active:</active> Summon 2 icy ghosts for 6 seconds that seek out nearby enemy champions. Ghosts reveal enemies on contact and slow them by 40% for between 2 and 5 seconds based on how far the ghosts have traveled (90 second cooldown).<hr><passive>QUEST:</passive> Earn 750 gold using this item.<br><passive>REWARD:</passive> <font color=\'#CFBF84\'>Tribute</font> is upgraded into <font color=\'#CFBF84\'><a href=\'frostqueenslinequestreward\'>Queen\'s Tribute</a></font>.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Sends out seeking wraiths that track hidden enemies and slow them', 3),
	(3340, 'Warding Totem (Trinket)', 0, 0, 0, b'1', 'yellow; totem; trinket', '<groupLimit>Limited to 1 Trinket.</groupLimit><br><br><active>Active:</active> Consume a charge to place an invisible <font color=\'#BBFFFF\'>Stealth Ward</font> which reveals the surrounding area for <scaleLevel>90 - 120</scaleLevel> seconds. <br><br>Stores one charge every <scaleLevel>240 - 120</scaleLevel> seconds, up to 2 maximum charges.<br><br>Ward duration and recharge time gradually improve with level.<br><br><rules>(Limit 3 <font color=\'#BBFFFF\'>Stealth Wards</font> on the map per player.)</rules>', 'Periodically place a Stealth Ward', 1),
	(3345, 'Soul Anchor (Trinket)', 0, 0, 0, b'0', '', '<groupLimit>Limited to 1 Trinket.</groupLimit><br><br><active>Active:</active> Consumes a charge to instantly revive at your Summoner Platform and grants 125% Movement Speed that decays over 12 seconds.<br><br><rules>Additional charges are gained at levels 9 and 14.</rules><br><br><font color=\'#BBFFFF\'>(Max: 2 charges)</font></rules><br><br>', 'Consumes charge to revive champion.', 1),
	(3348, 'Arcane Sweeper', 0, 0, 0, b'0', ';', '<active>UNIQUE Active - Hunter\'s Sight:</active> An arcane mist grants vision in the target area for 5 seconds, revealing enemy champions and granting <font color=\'#ee91d7\'>True Sight</font> of traps in the area for 3 seconds (90 second cooldown).', 'Activate to reveal a nearby area of the map', 1),
	(3361, 'Greater Stealth Totem (Trinket)', 175, 250, 250, b'0', 'yellow;', '<groupLimit>Limited to 1 Trinket.</groupLimit><levelLimit> *Level 9+ required to upgrade.</levelLimit><stats></stats><br><br><unique>UNIQUE Active:</unique> Consume a charge to place an invisible ward that reveals the surrounding area for 180 seconds.  Stores a charge every 60 seconds, up to 2 total. Limit 3 <font color=\'#BBFFFF\'>Stealth Wards</font> on the map per player.<br><br><rules>(Trinkets cannot be used in the first 30 seconds of a game. Selling a Trinket will disable Trinket use for 120 seconds).</rules>', 'Periodically place a Stealth Ward', 1),
	(3362, 'Greater Vision Totem (Trinket)', 175, 250, 250, b'0', 'yellow;', '<groupLimit>Limited to 1 Trinket.</groupLimit><levelLimit> *Level 9+ required to upgrade.</levelLimit><stats></stats><br><br><unique>UNIQUE Active:</unique> Places a visible ward that reveals the surrounding area and invisible units in the area until killed (120 second cooldown). Limit 1 <font color=\'#BBFFFF\'>Vision Ward</font> on the map per player.<br><br><rules>(Trinkets cannot be used in the first 30 seconds of a game. Selling a Trinket will disable Trinket use for 120 seconds).</rules>', 'Periodically place a Vision Ward', 1),
	(3363, 'Farsight Alteration', 0, 0, 0, b'1', 'blue; totem; trinket', '<levelLimit>Level 9+ required to upgrade.</levelLimit><br><groupLimit>Limited to 1 Trinket.</groupLimit><br><br>Alters the <font color=\'#FFFFFF\'>Warding Totem</font> Trinket:<br><br><stats><font color=\'#00FF00\'>+</font> Massively increased cast range (+650%)<br><font color=\'#00FF00\'>+</font> Infinite duration and does not count towards ward limit<br><font color=\'#FF0000\'>-</font> <font color=\'#FF6600\'>10% increased cooldown</font><br><font color=\'#FF0000\'>-</font> <font color=\'#FF6600\'>Ward is visible, fragile, untargetable by allies</font><br><font color=\'#FF0000\'>-</font> <font color=\'#FF6600\'>45% reduced ward vision radius</font><br><font color=\'#FF0000\'>-</font> <font color=\'#FF6600\'>Cannot store charges</font></stats>', 'Grants increased range and reveals the targetted area', 1),
	(3364, 'Oracle Lens', 0, 0, 0, b'1', 'red; lens; trinket', '<groupLimit>Limited to 1 Trinket.</groupLimit><br><br><active>Active:</active> Scans around you, warning against hidden hostile units, and revealing invisible traps and revealing / disabling nearby wards for 10 seconds (90 to 60 second cooldown).</maintext>', 'Disables nearby invisible wards and traps for a duration', 1),
	(3371, 'Molten Edge', 2380, 3400, 0, b'1', ';ie;Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+100 Attack Damage</font></stats><br><br><unique>UNIQUE Passive:</unique> Doubles your critical strike chance.<br><unique>UNIQUE Passive:</unique> 10% of critical strike damage is converted to True Damage.', 'Massively enhances critical strikes', 3),
	(3373, 'Forgefire Cape', 2030, 2900, 0, b'1', ';Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+625 Health</font><br><font color=\'#FFFFFF\'>+90 Armor</font></stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 25 (+1 per champion level) magic damage per second to nearby enemies. Deals 50% bonus damage to minions and monsters.', 'Constantly deals damage to nearby enemies', 4),
	(3374, 'Rabadon\'s Deathcrown', 2520, 3600, 0, b'1', ';dc;banksys;hat;Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+175 Ability Power</font>  </stats><br><br><unique>UNIQUE Passive:</unique> Increases Ability Power by 40%.', 'Massively increases Ability Power', 3),
	(3379, 'Infernal Mask', 2100, 3000, 0, b'1', ';Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+550 Health</font><br><mana>+300 Mana</mana><br><font color=\'#FFFFFF\'>+90 Magic Resist</font><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Eternity:</unique> 15% of damage taken from champions is gained as Mana. Spending Mana restores 20% of the cost as Health, up to 25 per spell cast.<br><aura>UNIQUE Aura:</aura> Nearby enemy champions take 15% more magic damage.', 'Nearby enemies take more magic damage', 4),
	(3380, 'The Obsidian Cleaver', 2100, 3000, 0, b'1', ';bc;Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+550 Health</font><br><font color=\'#FFFFFF\'>+60 Attack Damage</font><br>+20% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> Dealing physical damage to an enemy champion Cleaves them, reducing their Armor by 4% for 6 seconds (stacks up to 6 times, up to 24%).<br><unique>UNIQUE Passive - Rage:</unique> Dealing physical damage grants 20 movement speed for 2 seconds. Assists on Cleaved enemy champions or kills on any unit grant 60 movement speed for 2 seconds instead. This Movement Speed is halved for ranged champions.', 'Dealing physical damage to enemy champions reduces their Armor', 4),
	(3382, 'Salvation', 1470, 2100, 0, b'1', ';Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+300 Health</font><br><font color=\'#FFFFFF\'>+150% Base Health Regen </font><br><font color=\'#FFFFFF\'>+200% Base Mana Regen </font><br>+10% Cooldown Reduction</stats><br><br><passive>UNIQUE Passive:</passive> +10% Heal and Shield Power<br><active>UNIQUE Active:</active> Target an area within 5500 range. After 2.5 seconds, call down a beam of light to heal allies for 10 (+20 per level of target) Health, burn enemy champions for 10% of their maximum Health as <font color=\'#FFFFFF\'>true</font> damage and deal 250 <font color=\'#FFFFFF\'>true</font> damage to enemy minions (120 second cooldown). Heal and Shield Power is 3 times as effective on Salvation\'s heal.<br><br>Can be used while dead.<br><br><rules>Half effect if the target has been affected by Redemption recently.</rules>', 'Activate to heal allies and damage enemies in an area', 4),
	(3383, 'Circlet of the Iron Solari', 1540, 2200, 0, b'1', ';Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+45 Armor</font><br><font color=\'#FFFFFF\'>+75 Magic Resist</font></stats><br><br><active>UNIQUE Active:</active> Grants a decaying shield to nearby allied champions for 2.5 seconds that absorbs up to 30 (+15 per level) <scaleHealth>(+20% of your bonus health)</scaleHealth> damage (120 second cooldown).<br><br><rules>Shield per level uses the higher of your level or the target\'s level.<br>Shield ratio scales with your level.<br>Shield amount is reduced to 25% if the target has been affected by another Locket of the Iron Solari in the last 20 seconds.</rules>', 'Activate to shield nearby allies from damage', 4),
	(3384, 'Trinity Fusion', 2613, 3733, 0, b'1', ';triforce;tons of damage;Ornn;forge;Masterwork', '<stats><font color=\'#FFFFFF\'>+350 Health</font><br><font color=\'#FFFFFF\'><mana>+350 Mana</mana></font><br><font color=\'#FFFFFF\'>+35 Attack Damage</font><br><font color=\'#FFFFFF\'>+50% Attack Speed</font><br>+20% Cooldown Reduction<br><font color=\'#FFFFFF\'>+8% Movement Speed</font></stats><br><br><unique>UNIQUE Passive - Rage:</unique> Basic attacks grant 20 Movement Speed for 2 seconds. Kills grant 60 Movement Speed instead. This Movement Speed bonus is halved for ranged champions.<br><unique>UNIQUE Passive - Spellblade:</unique> After using an ability, the next basic attack deals bonus physical damage equal to 200% of base Attack Damage on hit (1.5 second cooldown).', 'Tons of Damage', 4),
	(3385, 'Wooglet\'s Witchcrown', 2380, 3400, 0, b'1', ';hat;Ornn;Forge', '<stats><font color=\'#FFFFFF\'>+155 Ability Power</font><br>+45 Armor  </stats><br><br><unique>UNIQUE Passive:</unique> Increases Ability Power by 25%<br><active>UNIQUE Active:</active> Champion becomes invulnerable and untargetable for 2.5 seconds, but is unable to move, attack, cast spells, or use items during this time (120 second cooldown).', 'Massively increases Ability Power and can be activated to enter stasis', 4),
	(3386, 'Zhonya\'s Paradox', 2030, 2900, 0, b'1', ';zhg;zonyas;ornn;forge', '<stats><font color=\'#FFFFFF\'>+100 Ability Power</font><br><font color=\'#FFFFFF\'>+60 Armor</font><br>+10% Cooldown Reduction</stats><br><br><active>UNIQUE Active - Stasis:</active> Champion becomes invulnerable and untargetable for 2.5 seconds, but is unable to move, attack, cast spells, or use items during this time (120 second cooldown).', 'Activate to become invincible but unable to take actions', 4),
	(3387, 'Frozen Fist', 1890, 2700, 0, b'1', ';frozen fist;Ornn', '<stats><font color=\'#FFFFFF\'>+95 Armor</font><br>+20% Cooldown Reduction<br><font color=\'#FFFFFF\'>+700 Mana</font></stats><br><br><unique>UNIQUE Passive - Spellblade:</unique> After using an ability, the next basic attack deals bonus physical damage equal to 100% of base Attack Damage in an area and creates an icy zone for 2 seconds that slows Movement Speed by 30% (1.5 second cooldown).<br><br>Size of zone increases with bonus armor.', 'Basic attacks create a slow field after spell cast', 4),
	(3388, 'Youmuu\'s Wraithblade', 2030, 2900, 0, b'1', ';lethality;Ornn', '<stats><font color=\'#FFFFFF\'>+75 Attack Damage</font><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> <font color=\'#FFFFFF\'>+25 <a href=\'Lethality\'>Lethality</a></font><br><unique>UNIQUE Passive:</unique> +40 Movement Speed out of Combat<br><active>UNIQUE Active:</active> Grants +20% Movement Speed for 6 seconds (45 second cooldown).', 'Activate to greatly increase Movement Speed', 4),
	(3389, 'Might of the Ruined King', 2240, 3200, 0, b'1', ';brk;bork;bork;bork;botrk;Ornn', '<stats><font color=\'#FFFFFF\'>+55 Attack Damage</font><br><font color=\'#FFFFFF\'>+40% Attack Speed</font><br>+12% Life Steal</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 8% of the target\'s current Health as bonus physical damage on hit.<br><active>UNIQUE Active:</active> Deals 100 magic damage to target champion and steals 25% of their Movement Speed for 3 seconds (90 second cooldown).<br><br><rules>Minimum bonus physical damage dealt is 15.<br>Maximum bonus physical damage dealt to monsters and minions is 60.<br>User\'s Life Steal is applied to bonus physical damage dealt.</rules>', 'Deals damage based on target\'s Health, can steal Movement Speed', 5),
	(3390, 'Luden\'s Pulse', 2240, 3200, 0, b'1', ';Ornn', '<stats><font color=\'#FFFFFF\'>+120 Ability Power</font><br><mana><font color=\'#FFFFFF\'>+850 Mana</font></mana><br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Haste:</unique> This item gains an additional 10% Cooldown Reduction.<br><unique>UNIQUE Passive - Echo:</unique> Gain charges upon moving or casting. At 100 charges, the next damaging spell hit expends all charges to deal 100 (+10% of Ability Power) bonus magic damage to up to 4 targets on hit.', 'Increases Ability Power, Mana, and Cooldown Reduction', 4),
	(3400, '\'Your Cut\'', 0, 0, 0, b'0', '', '<spellPassive>Click to Consume:</spellPassive> Gain <gold>Gold</gold>!', '', 1),
	(3401, 'Remnant of the Aspect', 720, 1800, 550, b'1', 'Eye of the Aspect;', '<stats>+350 Health<br>+200% Base Health Regen <br>+10% Cooldown Reduction<br>+1 Gold per 10 seconds </stats><br><br><unique>UNIQUE Passive - Spoils of War:</unique> Melee basic attacks execute minions below 320 (+30 per level) Health. Killing a minion heals the owner and the nearest allied champion for 50 Health (+2% missing health) and grants them kill Gold. 50% healing if the owner is ranged. These effects require a nearby ally. Recharges every 20 seconds. Max 4 charges.<hr><passive>QUEST:</passive> Earn 500 gold using this item.<br><passive>REWARD:</passive> Gain <active>UNIQUE Active - Warding:</active> Consumes a charge to place a <font color=\'#BBFFFF\'>Stealth Ward</font> that reveals the surrounding area for 150 seconds.  Holds up to 4 charges which refill upon visiting the shop.<br><br><groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit>', 'Provides Health and Stealth Wards over time', 3),
	(3410, 'Head of Kha\'Zix', 0, 0, 0, b'0', '', '<unique>UNIQUE Active - Sweeping Lens:</unique> Reveals and disables nearby invisible traps and invisible wards for 6 seconds in a medium radius and grants detection of invisible units for 10 seconds (60 second cooldown).<br><br><unique>UNIQUE Passive - Mementos of the Hunt:</unique> Rengar collects trophies when killing Champions and gains bonus effects based on how many trophies he has. Kills and assists grant 1 trophy.<br><br><passive>3 Trophies:</passive> Rengar gains 25 Movement Speed whilst out of combat or in brush. <br><passive>6 Trophies:</passive> Increases the range of Rengar\'s Leap by 125.<br><passive>12 Trophies:</passive> Thrill of the Hunt\'s duration is increased by 5 seconds.<br><passive>20 Trophies:</passive> Thrill of the Hunt\'s Movement Speed while stealthed is doubled.', '', 1),
	(3416, 'Head of Kha\'Zix', 0, 0, 0, b'0', '', '<unique>UNIQUE Active - Scrying:</unique> Reveals a small location within 4000 range for 2 seconds. Enemy champions found will be revealed for 5 seconds (90 second cooldown).<br><br><unique>UNIQUE Passive - Mementos of the Hunt:</unique> Rengar collects trophies when killing Champions and gains bonus effects based on how many trophies he has. Kills and assists grant 1 trophy.<br><br><passive>3 Trophies:</passive> Rengar gains 25 Movement Speed whilst out of combat or in brush. <br><passive>6 Trophies:</passive> Increases the range of Rengar\'s Leap by 125.<br><passive>12 Trophies:</passive> Thrill of the Hunt\'s duration is increased by 5 seconds.<br><passive>20 Trophies:</passive> Thrill of the Hunt\'s Movement Speed while stealthed is doubled.', '', 1),
	(3422, 'Head of Kha\'Zix', 0, 0, 0, b'0', '', '<unique>UNIQUE Passive - Mementos of the Hunt:</unique> Rengar collects trophies when killing Champions and gains bonus effects based on how many trophies he has. Kills and assists grant 1 trophy.<br><br><passive>3 Trophies:</passive> Rengar gains 25 Movement Speed whilst out of combat or in brush. <br><passive>6 Trophies:</passive> Increases the range of Rengar\'s Leap by 125.<br><passive>12 Trophies:</passive> Thrill of the Hunt\'s duration is increased by 5 seconds.<br><passive>20 Trophies:</passive> Thrill of the Hunt\'s Movement Speed while stealthed is doubled.', '', 1),
	(3455, 'Head of Kha\'Zix', 0, 0, 0, b'0', '', '<unique>UNIQUE Passive - Mementos of the Hunt:</unique> Rengar collects trophies when killing Champions and gains bonus effects based on how many trophies he has. Kills and assists grant 1 trophy.<br><br><passive>3 Trophies:</passive> Rengar gains 25 Movement Speed whilst out of combat or in brush. <br><passive>6 Trophies:</passive> Increases the range of Rengar\'s Leap by 125.<br><passive>12 Trophies:</passive> Thrill of the Hunt\'s duration is increased by 5 seconds.<br><passive>20 Trophies:</passive> Thrill of the Hunt\'s Movement Speed while stealthed is doubled.', '', 1),
	(3460, 'Golden Transcendence', 0, 0, 0, b'0', '', '<unique>Active:</unique> Use this trinket to teleport to one of the battle platforms. Can only be used from the summoning platform.<br><br><i><font color=\'#FDD017\'>\'\'It is at this magical precipice where a champion is dismantled, reforged, and empowered.\'\'</font></i>', '', 1),
	(3461, 'Golden Transcendence (Disabled)', 0, 0, 0, b'0', '', '<unique>Active:</unique> Use this trinket to teleport to one of the battle platforms. Can only be used from the summoning platform.<br><br><i><font color=\'#FDD017\'>\'\'It is at this magical precipice where a champion is dismantled, reforged, and empowered.\'\'</font></i>', '', 1),
	(3462, 'Seer Stone (Trinket)', 0, 0, 0, b'0', 'blue;', '<groupLimit>Limited to 1 Trinket.</groupLimit><br><br><active>Active:</active> Reveals a small area within <font color=\'#FFFFF\'>2500</font> range for 3 seconds. Enemy champions will be revealed for 5 seconds (60 second cooldown)', 'Briefly reveals a nearby targeted area', 1),
	(3504, 'Ardent Censer', 1610, 2300, 650, b'1', '', '<stats>+60 Ability Power<br>+10% Cooldown Reduction<br><mana>+50% Base Mana Regen </mana></stats><br><br><unique>UNIQUE Passive:</unique> +10% Heal and Shield Power<br><unique>UNIQUE Passive:</unique> +8% Movement Speed<br><unique>UNIQUE Passive:</unique> Whenever you heal or shield an ally, you and your ally gain 10% - 30% Attack Speed and your attacks deal an additional 5 - 20 on-hit magic damage for 6 seconds. <br><br><rules>This does not include regeneration effects. Bonus effects are based on target\'s level.</rules>', 'Shield and heal effects on other units grant both of you Attack Speed and their attacks deal additional on-hit magic damage.', 3),
	(3508, 'Essence Reaver', 2100, 3000, 250, b'1', ';', '<stats>+75 Attack Damage<br>+20% Cooldown Reduction<br><mana>+300 Mana</mana></stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks refund 1% of your missing mana.<br><unique>UNIQUE Passive:</unique> After you cast your ultimate, your next basic attack within 10 seconds grants you <unlockedPassive>Essence Flare</unlockedPassive> for 6 seconds (30 second cooldown).<br><br><unlockedPassive>Essence Flare:</unlockedPassive> Gain 50% attack speed, and basic attacks refund 20% of your remaining non-ultimate cooldowns.', 'Attack and cast spells faster after your ultimate', 3),
	(3512, 'Zz\'Rot Portal', 1890, 2700, 1080, b'1', ';Void Gate', '<stats>+55 Armor<br>+55 Magic Resist<br>+125% Base Health Regen <br></stats><br><unique>UNIQUE Passive - Point Runner:</unique> Builds up to +20% Movement Speed over 2 seconds while near turrets, fallen turrets and Void Gates.<br><active>UNIQUE Active:</active> Spawns a <a href=\'VoidGate\'>Void Gate</a> for 120 seconds (120 second cooldown).<br><br>Every 4 seconds the gate makes a <a href=\'Voidspawn\'>Voidspawn</a>. The first and every fourth Voidspawn gains 15% of maximum Health as damage.', 'Makes a Voidspawn generating Void Gate to push a lane with.', 3),
	(3513, 'Eye of the Herald', 0, 0, 0, b'0', ';Herald\'s Eye', '<br><unique>UNIQUE Passive - Glimpse of the Void:</unique> The holder of the Eye of the Herald has Empowered Recall.<br><br><active>UNIQUE Active:</active> Channel for 3.5 seconds to crush the Eye of the Herald, summoning the Rift Herald to siege enemy turrets.<br><br>The Eye of the Herald will be lost to the Void if not used within 240 seconds.</font>', 'Eye of the Herald - a Gift of the Void.', 1),
	(3514, 'Eye of the Herald', 0, 0, 0, b'0', ';Herald\'s Eye', '<br><unique>UNIQUE Passive - Glimpse of the Void:</unique> The holder of the Eye of the Herald has Empowered Recall.<br><br><active>UNIQUE Active:</active> Channel for 3.5 seconds to crush the Eye of the Herald, summoning the Rift Herald to siege enemy turrets.<br><br>The Eye of the Herald will be lost to the Void if not used within 240 seconds.', 'Eye of the Herald - a Gift of the Void.', 1),
	(3520, 'Ghost Poro', 0, 0, 0, b'0', '', '<subtitleLeft><font color=\'#FFFFFF\'>(Trinket)</font></subtitleLeft><br><mainText><active>Active:</active> Command your Ghost Poro to stay in a brush. Gain additional stats if you or your Ghost Poro are in enemy territory.<mainText></mainText>', '', 1),
	(3599, 'The Black Spear', 0, 0, 0, b'1', ';spear', '<stats></stats><br><active>Active:</active> Offer to bind with an ally for the remainder of the game, becoming Oathsworn Allies. Oathsworn empowers you both while near one another.', 'Kalista\'s spear that binds an Oathsworn Ally.', 1),
	(3630, 'Siege Teleport', 7, 10, 10, b'0', '', '<unique>Active:</unique> Use this trinket to teleport to one of your team\'s port pads. Can only be used from the summoning platform.', '', 1),
	(3631, 'Siege Ballista', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Deploys a ballista that shoots the closest turret.</font><br><br>Places a long range ballista if within 2200 range of an enemy turret. After a 5 second delay, it will begin firing at the nearest enemy turret, dealing heavy damage. If the targeted turret expires, the ballista will as well.', 'Place a long range anti-turret ballista', 1),
	(3633, 'Siege Teleport', 7, 10, 10, b'0', '', '<unique>Active:</unique> Use this trinket to teleport to one of your team\'s port pads. Can only be used from the summoning platform.', '', 1),
	(3634, 'Tower: Beam of Ruination', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Attach, then recast to fire a damaging beam from a turret to your cursor.</font><br><br><font color=\'#FF9900\'>First Cast:</font> Attach a Slayer Beam to the target turret that can be fired 3 times.<br></br><font color=\'#FF9900\'>Next Three Casts:</font> Fires the attached beam towards your cursor, dealing 30/level + 30% of the hit target\'s maximum health (20% damage to minions) in magic damage to all targets in a line.<br></br><br></br>Beam will last 15 seconds, or until it has been fired 3 times.', 'Attaches a three shot beam to a turret which can then be aimed and fired', 1),
	(3635, 'Port Pad', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Deploy an additional teleport target.</font><br><br>Places a Port Pad at target location. After a 4 second delay, it activates, allowing you or your allies to teleport to it from base.', 'Creates another point for your team to Teleport to', 1),
	(3636, 'Tower: Storm Bulwark', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Makes a turret go invulnerable, then rain fire.</font><br><br>Makes the target turret invulnerable for 6 seconds. Two seconds before expiry, it unleashes a missile volley, dealing 2600 true damage over the remaining time to all nearby enemies.<br><br>Cannot be used on the same turret more than once in 15 seconds.', 'Make a turret go invulnerable while charging a powerful barrage', 1),
	(3637, 'Nexus Siege: Siege Weapon Slot', 7, 10, 10, b'0', '', 'In Nexus Siege, Summoner Spells are replaced with Siege Weapon Slots. Spend Crystal Shards to buy single-use Siege Weapons from the item shop, then use your Summoner Spell keys to activate them!', '', 1),
	(3640, 'Flash Zone', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Allows team to cast Flash repeatedly in a limited zone.</font><br><br>Creates a magic zone for your team for 5 seconds. While in this zone, you and your allies have your summoner spells replaced by an instant cast blink that moves you to any location in the zone (1 second cooldown).', 'Allows you and allies to repeatedly flash while in a zone', 1),
	(3641, 'Vanguard Banner', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Place a banner that buffs minions.</font><br><br>Place a Vanguard Banner at target location. After a 2 second delay, any nearby minions will be granted a buff, increasing their damage by 50%, and granting them 50 Armor and 100 Magic Resistance while within range.', 'Strengthens nearby minions', 1),
	(3642, 'Siege Refund', 0, 0, 0, b'1', '', 'Refunds all purchased Siege Weapons for their full price.', 'Refunds all current Siege Weapons', 1),
	(3643, 'Entropy Field', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Stun minions and slow champions in an area.</font><br><br>Places an Entropy Field at target location for 5 seconds.  Enemy minions and Siege Ballistas trapped in the field are unable to move or attack while in the field.  Enemy champions in the field have their Movement Speed reduced by 25%.', 'Places a field that stuns enemy minions and slows champions', 1),
	(3645, 'Seer Stone (Trinket)', 0, 0, 0, b'0', 'blue;', '<groupLimit>Limited to 1 Trinket.</groupLimit><br><br><active>Active:</active> Reveals a small area within <font color=\'#FFFFF\'>1400</font> range for 3 seconds. Enemy champions will be revealed for 5 seconds (60 second cooldown)', 'Briefly reveals a nearby targeted area', 1),
	(3647, 'Shield Totem', 0, 0, 0, b'1', '', '<br><font color=\'#FF9900\'>Place a totem that shields nearby deployables.</font><br><br>Places a Shield Totem at target location. After a 2 second delay, the totem will activate, granting a 2 (+1 per additional Shield Totem) strength shield to all nearby deployables.', 'Grants bonus health to nearby Siege Weapons', 1),
	(3648, 'Siege Teleport (Inactive)', 0, 0, 0, b'0', '', '', '', 1),
	(3649, 'Siege Sight Warder', 0, 0, 0, b'0', '', '<groupLimit>Limited to 1 Trinket.</groupLimit><br><br><active>Active:</active> Places a <font color=\'#FFFFFF\'>Stealth Ward</font> that lasts <font color=\'#FFFFFF\'>30</font> seconds (30 second cooldown).', '', 1),
	(3671, 'Enchantment: Warrior', 1138, 1625, 525, b'1', ';', '<stats>+60 Attack Damage<br>+10% Cooldown Reduction</stats>', '', 3),
	(3672, 'Enchantment: Cinderhulk', 998, 1425, 525, b'1', ';', '<stats>+325 Health<br>+15% Bonus Health</stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 7 (+2 per champion level) magic damage a second to nearby enemies while in combat. Deals 100% bonus damage to monsters. ', '', 3),
	(3673, 'Enchantment: Runic Echoes', 1138, 1625, 340, b'1', ';', '<stats>+60 Ability Power<br>+7% Movement Speed</stats><br><br><unique>UNIQUE Passive - Echo:</unique> Gain charges upon moving or casting. At 100 charges, the next damaging spell hit expends all charges to deal 60 (+10% of Ability Power) bonus magic damage to up to 4 targets on hit.<br><br>This effect deals 250% damage to Large Monsters. Hitting a Large Monster with this effect will restore 18% of your missing Mana.', '', 3),
	(3675, 'Enchantment: Bloodrazor', 1138, 1625, 625, b'1', ';', '<stats>+50% Attack Speed</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 4% of the target\'s maximum Health in bonus physical damage (max 75 vs. monsters and minions) on hit.', '', 3),
	(3680, 'Frosted Snax', 0, 0, 0, b'1', '', '<active>Active - <a href=\'FeedTheKing\'>Feed The King</a>:</active> The King lobs many projectiles at far-away enemies, each dealing <scaleLevel>213-775</scaleLevel> magic damage to targets in the center of the impact, scaling down to <scaleLevel>85-310</scaleLevel> on the edge. (120s cooldown)', 'King: Fires a barrage of icy artillery', 1),
	(3681, 'Super Spicy Snax', 0, 0, 0, b'1', '', '<active>Active - <a href=\'FeedTheKing\'>Feed The King</a>:</active> The King breathes fire for 4 seconds, dealing <scaleLevel>705-1479</scaleLevel> true damage over the duration to enemies caught in the cone. Deals up to 560 true damage to Turrets. (120s cooldown)', 'King: Shoots flames that burn units and Turrets', 1),
	(3682, 'Espresso Snax', 0, 0, 0, b'1', '', '<active>Active - <a href=\'FeedTheKing\'>Feed The King</a>:</active> The King leaps into the air and crashes down twice, knocking enemies away and dealing <scaleLevel>40-190</scaleLevel> physical damage. He also gains a decaying shield for <font color=\'#FF3300\'>20% of his maximum health</font>, lasting 4 seconds. (30s cooldown)', 'King: Knocks back and grants a large shield', 1),
	(3683, 'Rainbow Snax Party Pack!', 0, 0, 0, b'1', '', '<active>Active - <a href=\'FeedTheKing\'>Feed The King</a>:</active> The King tosses many Snax behind the enemy, attracting Poros which dash back towards him. Enemy champions hit will be knocked forwards and dealt <scaleLevel>230-680</scaleLevel> physical damage. (120s cooldown)', 'King: Poros knock enemies towards him', 1),
	(3690, 'Cosmic Shackle', 0, 0, 0, b'1', ';', '<passive>Passive - Cosmic Shackle: </passive>Death Sentence pulls much farther (based on the target\'s Missing Health), and can be ignited by the Dark Star to do more damage.<br><br><flavorText>\'\'A still more glorious dawn awaits.\'\'</flavorText>', '', 1),
	(3691, 'Singularity Lantern', 0, 0, 0, b'1', ';', '<passive>Passive - Singularity Lantern: </passive>Dark Passage automatically saves disabled allies. However, it no longer provides a shield.<br><br><flavorText>\'\'The stars call to us.\'\'</flavorText>', '', 1),
	(3692, 'Dark Matter Scythe', 0, 0, 0, b'1', ';', '<passive>Passive - Dark Matter Scythe: </passive>Flay\'s on-hit passive charges damage very quickly. Flay will throw enemies much farther (based on their Missing Health).<br><br><flavorText>\'\'If you want to make a Singularity from scratch, you must first destroy the universe.\'\'</flavorText>', '', 1),
	(3693, 'Gravity Boots', 0, 0, 0, b'1', ';', '<passive>Passive - Mass Conversion: </passive>Thresh\'s Health represents how far enemy pulls and pushes will send him. At lower Health, he will be thrown farther.<br><br><passive>Passive - Terminus Dwellers: </passive>Abyss Scuttlers emerge periodically, and will scurry towards the Dark Star when attacked. Gravitational disturbances will temporarily attract many of them.', '', 1),
	(3694, 'Cloak of Stars', 0, 0, 0, b'1', ';', '<passive>Passive - Stellar Spirit: </passive>Upon spawning, Thresh is invulnerable, untargetable, cannot cast, and is able to travel in open space. This is lost when stepping foot on stable ground.<br><br>Being saved by Dark Passage or using Death Sentence on one of the three <font color=\'#3091ec\'>Gravity Anchors</font> will briefly put you into this invulnerable state and break enemy chains on you.', '', 1),
	(3695, 'Dark Star Sigil', 0, 0, 0, b'1', ';', '<passive>Passive - Stellar Fealty: </passive>Thresh cannot kill units directly - their souls, experience, and gold belong to the Dark Star.<br><br>Pulling or pushing an enemy into the Dark Star will destroy them instantly, scoring points for your team (+5, or +1 for Abyss Scuttlers).<br><br>Winning a round requires 100 points, and the final points must be from a champion kill.', '', 1),
	(3706, 'Stalker\'s Blade', 700, 1000, 300, b'1', ';jungle;Jungle;jangle', '<groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br>+10% Life Steal vs. Monsters<br><br><unique>UNIQUE Passive - Chilling Smite:</unique> Smite can be cast on enemy champions, dealing reduced true damage and stealing 20% Movement Speed for 2 seconds.<br><unique>UNIQUE Passive - Tooth / Nail:</unique> Basic attacks vs. monsters deal 40 bonus damage.  Damaging a monster with a spell or attack steals 30 Health over 5 seconds and burns them for 80 magic damage.<mana> While in the jungle or river, regenerate up to 8 Mana per second based on your missing Mana.</mana> This item grants <font color=\'#99BBBB\'><a href=\'SpecialJungleExperience\'>Monster Hunter</a></font>.', 'Lets your Smite slow Champions', 2),
	(3715, 'Skirmisher\'s Sabre', 700, 1000, 300, b'1', ';jungle;Jungle', '<groupLimit>Limited to 1 Gold Income or Jungle item.</groupLimit><br><br>+10% Life Steal vs. Monsters<br><br><unique>UNIQUE Passive - Challenging Smite:</unique> Smite can be cast on enemy champions, marking them for 4 seconds. While marked, the target is revealed, your basic attacks deal bonus true damage over 3 seconds, and their damage to you is reduced by 20%.<br>Basic attacks vs. monsters deal 40 bonus damage. Damaging a monster with a spell or attack steals 30 Health over 5 seconds and burns them for 80 magic damage. While in the jungle or river, regenerate up to 8 Mana per second based on your missing Mana. This item grants <font color=\'#99BBBB\'><a href=\'SpecialJungleExperience\'>Monster Hunter</a></font>.', 'Lets your Smite mark Champions, giving you combat power against them.', 2),
	(3742, 'Dead Man\'s Plate', 2030, 2900, 1100, b'1', ';juggernaut;dreadnought', '<stats>+425 Health<br>+60 Armor</stats><br><br><unique>UNIQUE Passive - Dreadnought:</unique> While moving, build stacks of Momentum, increasing movement speed by up to 60 at 100 stacks. Momentum decays while under the effect of a stun, taunt, fear, polymorph, or immobilize effect.<br><unique>UNIQUE Passive - Crushing Blow:</unique> Basic attacks deal 1 magic damage per stack of Momentum, discharging all stacks. At max stacks, if the attacker is melee, they also slow the target by 50% for 1 second.<br><br><flavorText>\'\'There\'s only one way you\'ll get this armor from me...\'\' - forgotten namesake</flavorText>', 'Build momentum as you move around then smash into enemies.', 3),
	(3748, 'Titanic Hydra', 2450, 3500, 575, b'1', ';juggernaut', '<stats>+450 Health<br>+40 Attack Damage<br>+100% Base Health Regen </stats><br><br><unique>UNIQUE Passive - Cleave:</unique> Basic attacks deal 5 + 1% of your maximum health as bonus physical damage  to your target and 40 + 2.5% of your maximum health as physical damage  to other enemies in a cone on hit.<br><active>UNIQUE Active - Crescent:</active> Cleave damage to all targets is increased to 40 + 10% of your maximum health as bonus physical damage  in a larger cone for your next basic attack (20 second cooldown).<br><br><rules>(Unique Passives with the same name don\'t stack.)</rules>', 'Deals area of effect damage based on owner\'s health', 3),
	(3751, 'Bami\'s Cinder', 630, 900, 500, b'1', ';', '<stats>+200 Health  </stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 5 (+1 per champion level) magic damage per second to nearby enemies. Deals 100% bonus damage to minions and monsters.', 'Grants Health and Immolate Aura', 2),
	(3800, 'Righteous Glory', 1855, 2650, 1100, b'1', ';', '<stats>+400 Health<br><mana>+300 Mana</mana><br>+30 Armor<br>+100% Base Health Regen <br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Active:</unique> Grants 75% Movement Speed when moving towards enemies or enemy turrets for 4 seconds. Once near an enemy (or after 4 seconds) a shockwave is emitted, slowing nearby enemy champion Movement Speed by 75% for 2 second(s) (90 second cooldown).', 'Grants Health, Mana, and Armor. Activate to speed towards enemies and slow them.', 3),
	(3801, 'Crystalline Bracer', 455, 650, 100, b'1', ';', '<stats>+200 Health<br>+50% Base Health Regen </stats>', 'Grants Health and Health Regen', 2),
	(3802, 'Lost Chapter', 910, 1300, 80, b'1', ';', '<stats>+40 Ability Power<br><mana>+300 Mana</mana></stats><br><br><unique>UNIQUE Passive - Haste:</unique> +10% Cooldown Reduction<br><unique>UNIQUE Passive:</unique> Upon levelling up, restores 20% of your maximum Mana over 3 seconds.', 'Restores Mana upon levelling up.', 2),
	(3812, 'Death\'s Dance', 2450, 3500, 625, b'1', ';Bloodbag', '<stats>+80 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> Heal for 15% of damage dealt. This is 33% as effective for Area of Effect damage.<br><unique>UNIQUE Passive:</unique> 30% of damage taken is dealt as a Bleed effect over 3 seconds instead.', 'Trades incoming damage now for incoming damage later', 3),
	(3813, 'Space Death\'s Dance', 2450, 3500, 625, b'1', ';Bloodbag', '<stats>+80 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive:</unique> Heal for 4% of damage dealt. This is 33% as effective for Area of Effect damage.<br><unique>UNIQUE Passive:</unique> 30% of damage taken is dealt as a Bleed effect over 3 seconds instead.', 'Trades incoming damage now for incoming damage later', 3),
	(3814, 'Edge of Night', 2100, 3000, 625, b'1', ';lethality', '<stats>+250 Health<br>+55 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> +18 <a href=\'Lethality\'>Lethality</a><br><unique>UNIQUE Active - Night\'s Veil:</unique> Channel for 1 second to grant a spell shield that blocks the next enemy ability. Lasts for 7 seconds (40 second cooldown).<br><br><rules>(Can move while channeling, but taking damage breaks the channel.)</rules>', 'Blocks an incoming enemy spell.', 3),
	(3901, 'Fire at Will', 0, 0, 0, b'1', '', 'Requires 500 Silver Serpents.<br><br><unique>UNIQUE Passive:</unique> Cannon Barrage fires at an increasing rate over time (additional 6 waves over the duration).', 'Cannon Barrage gains extra waves', 1),
	(3902, 'Death\'s Daughter', 0, 0, 0, b'1', '', 'Requires 500 Silver Serpents.<br><br><unique>UNIQUE Passive:</unique> Cannon Barrage additionally fires a mega-cannonball at center of the Barrage, dealing 300% true damage and slowing them by 60% for 1.5 seconds. ', 'Cannon Barrage fires a mega-cannonball', 1),
	(3903, 'Raise Morale', 0, 0, 0, b'1', '', 'Requires 500 Silver Serpents.<br><br><unique>UNIQUE Passive:</unique> Allies in the Cannon Barrage gain 30% Movement Speed for 2 seconds.', 'Cannon Barrage hastes allies', 1),
	(3905, 'Twin Shadows', 1680, 2400, 650, b'1', ';spooky;spooky ghosts', '<stats>+70 Ability Power<br>+7% Movement Speed<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Active - Spectral Pursuit:</unique> Summons 2 spooky ghosts that hunt down nearby champions, revealing and Haunting them on contact. <br><br>Haunted enemies are slowed by 40% for up to 5 seconds based on the distance the ghosts travel. (90 second cooldown).', 'Increases Ability Power and Movement Speed', 3),
	(3907, 'Spellbinder', 2030, 2900, 800, b'1', '', '<stats>+120 Ability Power<br>+10% Movement Speed<br></stats><br><unique>UNIQUE Passive:</unique> Nearby allied and enemy spellcasts charge Spellbinder up to a cap (100 maximum). <br><unique>UNIQUE Active:</unique> Gain a maximum of 80 Ability Power and 50% decaying Movement Speed for 4 seconds. <br><br>Each spellcast stored contributes +0.8 Ability Power and +0.5% Movement Speed to the effect. (60 second cooldown).', 'Stores nearby spellcasts and can consume them to grant Movement Speed and Ability Power.', 3),
	(3916, 'Oblivion Orb', 1050, 1500, 665, b'1', '', '<stats>+25 Ability Power<br>+200 Health</stats><br><br><unique>UNIQUE Passive - Touch of Death:</unique> +15 <a href=\'FlatMagicPen\'>Magic Penetration</a>', 'Increases magic damage', 2),
	(4001, 'Ghostwalkers (Melee Only)', 700, 1000, 700, b'1', ';', '<groupLimit>Limited to 1 pair of boots.</groupLimit><br><br><unique>UNIQUE Active:</unique> Become Ghostly for 6 seconds, ignoring terrain collision. While inside terrain, gain 125 movement speed and become untargetable, stealthed, and silenced (60 second cooldown).<br><unique>UNIQUE Passive - Enhanced Movement:</unique> +45 Movement Speed<br><br><rules>(Ghostwalkers are unaffected by the Predator Rune.)</rules>', 'Enhances Movement Speed and grants temporary wall walking.', 2),
	(4003, 'Lifeline', 1050, 1500, 550, b'1', ';lethality', '<stats>+20 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> +8 <a href=\'Lethality\'>Lethality</a><br><unique>UNIQUE Active:</unique> Mark the ground beneath you. After 4 seconds, you will return to the marked location (120 second cooldown).', 'Marks the ground, and returns you there after a few moments', 2),
	(4004, 'Spectral Cutlass', 2100, 3000, 400, b'1', ';lethality', '<stats>+70 Attack Damage</stats><br><br><unique>UNIQUE Passive:</unique> +18 <a href=\'Lethality\'>Lethality</a><br><unique>UNIQUE Active:</unique> Mark your current location. After 4 seconds, you will return to the marked location (60 second cooldown).', 'Marks the ground, and returns you there after a few moments', 3),
	(4101, 'Pridestalker\'s Blade', 315, 450, 450, b'1', ';jungle;Jungle;jangle', '<unique>UNIQUE Passive - Tooth / Nail:</unique> Basic attacks vs. monsters deal 40 bonus damage.  Damaging a monster with a spell or attack steals 30 Health over 5 seconds and burns them for 80 magic damage.<mana> While in the jungle or river, regenerate up to 8 Mana per second based on your missing Mana.</mana><br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Kill monsters faster', 1),
	(4102, 'Enchantment: Warrior', 1838, 2625, 1075, b'1', '', '<stats>+65 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Chilling Smite:</unique> Smite can be cast on enemy champions, dealing reduced true damage and stealing 20% Movement Speed for 2 seconds.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Tons of Damage', 3),
	(4103, 'Enchantment: Cinderhulk', 1838, 2625, 1275, b'1', '', '<stats>+350 Health<br>+10% Bonus Health</stats><br><br><unique>UNIQUE Passive - Immolate:</unique> Deals 11 (+1 per champion level) magic damage a second to nearby enemies while in combat. Deals 200% bonus damage to minions and monsters.<br><br><unique>UNIQUE Passive - Chilling Smite:</unique> Smite can be cast on enemy champions, dealing reduced true damage and stealing 20% Movement Speed for 2 seconds.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Increases bonus Health and burns nearby enemies', 3),
	(4104, 'Enchantment: Runic Echoes', 1838, 2625, 925, b'1', '', '<stats>+80 Ability Power<br>+10% Cooldown Reduction<br><mana>+300 Mana</mana></stats><br><br><unique>UNIQUE Passive - Echo:</unique> Gain charges upon moving or casting. At 100 charges, the next damaging spell hit expends all charges to deal 60 (+10% of Ability Power) bonus magic damage to up to 4 targets on hit.<br><br>This effect deals 250% damage to Large Monsters. Hitting a Large Monster with this effect will restore 25% of your missing Mana.<br><br><unique>UNIQUE Passive - Chilling Smite:</unique> Smite can be cast on enemy champions, dealing reduced true damage and stealing 20% Movement Speed for 2 seconds.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Spells explode for bonus damage', 3),
	(4105, 'Enchantment: Bloodrazor', 1838, 2625, 1175, b'1', '', '<stats>+50% Attack Speed</stats><br><br><unique>UNIQUE Passive:</unique> Basic attacks deal 4% of the target\'s maximum Health in bonus physical damage (max 75 vs. monsters and minions) on hit.<br><br><unique>UNIQUE Passive - Chilling Smite:</unique> Smite can be cast on enemy champions, dealing reduced true damage and stealing 20% Movement Speed for 2 seconds.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Attacks deal bonus damage based on the target\'s maximum Health', 3),
	(4201, 'Doran\'s Lost Shield', 180, 450, 450, b'1', ';dshield', '<stats>+100 Health</stats><br><br><passive>Passive: </passive>Restores 15 Health every 5 seconds.<br><passive>Passive: </passive>Basic attacks deal an additional 5 physical damage to minions on hit.<br><unique>UNIQUE Passive:</unique> Regain an additional 20 health over 10 seconds after taking damage from an enemy champion.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Good defensive starting item', 1),
	(4202, 'Doran\'s Lost Blade', 180, 450, 450, b'1', ';dblade', '<stats>+8 Attack Damage<br>+80 Health<br>+8% Life Steal</stats><br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Good starting item for attackers', 1),
	(4203, 'Doran\'s Lost Ring', 160, 400, 400, b'1', ';dring', '<stats>+60 Health<br>+15 Ability Power<br><mana>+10 Mana per 5 seconds</mana></stats><br><br><passive>Passive: </passive>Basic attacks deal an additional 5 physical damage to minions on hit.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Good starting item for casters', 1),
	(4204, 'Doran\'s Lost Idol', 160, 400, 400, b'1', ';didol', '<stats>+10 Ability Power<br><mana>+75% Base Mana Regen </mana><br>+5% Heal and Shield Power</stats><br><br><passive>Passive: </passive>Basic attacks deal an additional 12 physical damage to minions on hit.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Good starting item for Enchanters', 1),
	(4301, 'Philosopher\'s Medallion', 180, 450, 450, b'1', ';Ancient Coin;Nomad\'s Medallion;Support', '<stats>+10% Cooldown Reduction<br>+50% Base Health Regen <br>+5 Gold per 10 seconds</stats><br><br><unique>UNIQUE Passive - Favor:</unique> Enemy minions killed by your allies sometimes drop coins that give either <font color=\'#D4AF37\'>40</font> gold or <font color=\'#44DDFF\'>10%</font> missing mana (minimum 20). Cannon minions always drop coins.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Grants gold and mana when nearby minions die that you didn\'t kill', 1),
	(4302, 'Heart of Targon', 160, 400, 400, b'1', ';Targon\'s Brace;Relic Shield;Support', '<stats>+60 Health<br>+50% Base Health Regen <br>+5 Gold per 10 seconds </stats><br><br><unique>UNIQUE Passive - Spoils of War:</unique> Melee basic attacks execute minions below 200 (+40 per level) Health. Killing a minion heals the owner and the nearest allied champion for 25 Health (+2% missing health) and grants them kill Gold. 50% healing if the owner is ranged. These effects require a nearby ally. Recharges every 20 seconds. Max 3 charges.<br><br><groupLimit>Limited to 1 Starter item.</groupLimit>', 'Kill minions periodically to heal and grant gold to a nearby ally', 1),
	(4401, 'Force of Nature', 2030, 2900, 1160, b'1', ';fon', '<stats>+90 Magic Resist<br>+200% Base Health Regen <br>+8% Movement Speed</stats><br><br><unique>UNIQUE Passive:</unique> Regenerate 1.5% maximum Health every second.', 'Movement Speed, Magic Resist, and max Health Regeneration', 3),
	(4402, 'Innervating Locket', 1960, 2800, 600, b'1', ';', '<stats>+400 Health<br><mana>+300 Mana</mana><br>+30 Attack Damage<br>+10% Cooldown Reduction</stats><br><br><unique>UNIQUE Passive - Eternity:</unique> 15% of damage taken from champions is gained as Mana. Spending Mana restores 20% of the cost as Health, up to 25 per spell cast.<br><br><unique>UNIQUE Passive:</unique> After using an ability, restore 8% missing Health and 3% missing Mana over 3 seconds.<br><br><rules><font color=\'#447777\'>\'\'Cast down the Noxians\'\' - Bobdyr, Temple Guardsman</font></rules>', 'Cast spells to heal', 3),
	(4403, 'Stat-Stick of Stoicism', 5136, 7337, 687, b'1', ';', '<stats>+250 Health<br><mana>+250 Mana</mana><br>+100% Base Health Regen <br><mana>+100% Base Mana Regen </mana><br>+30 Armor<br>+30 Magic Resist<br>+120 Ability Power<br>+70 Attack Damage<br>+50% Attack Speed<br>+30% Critical Strike Chance<br>+10% Life Steal<br>+10% Movement Speed<br>+20% Cooldown Reduction</stats><br><br><rules><font color=\'#447777\'>\'\'What if we only bought some of the stats?\'\'<br>\'\'Declined, we must have ALL of them.\'\'</font></rules>', 'Has ALL the stats', 3);
